INSERT INTO `sanpham` (`id`, `name`, `price`, `price_sale`, `image`, `description`, `views`, `id_danhmuc`, `duration`) VALUES
(1, 'Tour Hạ Long 2 Ngày 1 Đêm - Du Thuyền 5 Sao Sang Trọng', 2500000, 1990000, 'uploads/dest_halong.png', 'Trải nghiệm du thuyền 5 sao đẳng cấp tại Vịnh Hạ Long - Di sản thiên nhiên thế giới. Tour bao gồm trọn gói dịch vụ ăn uống, chèo thuyền Kayak, tham quan hang Sửng Sốt, đảo Ti Tốp và các hoạt động vui chơi giải trí trên du thuyền.', 125, 1, '2 ngày 1 đêm'),
(2, 'Tour Sapa 3 Ngày 2 Đêm - Chinh Phục Đỉnh Fansipan Hùng Vĩ', 3200000, 2790000, 'uploads/tour_sapa.png', 'Hành trình khám phá thị trấn sương mù Sapa, tham quan bản Cát Cát mộc mạc, tìm hiểu văn hóa bản địa của đồng bào H\'Mông và đặc biệt là trải nghiệm đi cáp treo chinh phục đỉnh Fansipan - nóc nhà Đông Dương huyền thoại.', 98, 1, '3 ngày 2 đêm'),
(3, 'Tour Đà Nẵng - Hội An - Bà Nà Hills 4 Ngày 3 Đêm', 4500000, 3990000, 'uploads/dest_danang.png', 'Khám phá con đường di sản Miền Trung. Chiêm ngưỡng Cầu Vàng nổi tiếng thế giới tại Bà Nà Hills, dạo bước trong khu phố cổ Hội An lung linh đèn lồng và thưởng thức ẩm thực đặc sắc của vùng đất Đà thành đáng sống.', 150, 2, '4 ngày 3 đêm'),
(4, 'Tour Nha Trang 3 Ngày 2 Đêm - Thiên Đường Biển Đảo Gọi Mời', 2900000, 2490000, 'uploads/tour_nhatrang2.png', 'Tận hưởng kỳ nghỉ tuyệt vời tại thành phố biển Nha Trang xinh đẹp. Tham quan Vinwonders, đi tàu khám phá Vịnh San Hô, tắm bùn khoáng nóng thư giãn và thưởng thức tiệc hải sản tươi ngon ngay trên bè.', 82, 2, '3 ngày 2 đêm'),
(5, 'Tour Đà Lạt 3 Ngày 3 Đêm - Thành Phố Ngàn Hoa Mộng Mơ', 2600000, 2190000, 'uploads/dest_dalat.png', 'Hành trình đến với thành phố tình yêu Đà Lạt. Khám phá các điểm check-in hot nhất hiện nay: Thung lũng Tình Yêu, đỉnh Langbiang, chùa Ve Chai kỳ vĩ và tận hưởng không khí mát lành của rừng thông nguyên sinh.', 112, 2, '3 ngày 3 đêm'),
(6, 'Tour Phú Quốc 3 Ngày 2 Đêm - Nghỉ Dưỡng Tại Đảo Ngọc', 4800000, 4200000, 'uploads/hotel_famiana.png', 'Trải nghiệm thiên đường nghỉ dưỡng Phú Quốc. Tận hưởng làn nước trong xanh tại Bãi Sao, lặn ngắm san hô tại Nam Đảo, tham quan chợ đêm và Sunset Sanato ngắm hoàng hôn buông xuống biển Tây cực đẹp.', 143, 3, '3 ngày 2 đêm'),
(7, 'Tour Miền Tây Sông Nước 2 Ngày 1 Đêm - Mỹ Tho - Bến Tre - Cần Thơ', 1800000, 1490000, 'uploads/tour_mientay1.png', 'Về miền Tây trải nghiệm đi đò chèo dưới rặng dừa nước, tham quan lò kẹo dừa Bến Tre, thưởng thức trái cây miệt vườn và đờn ca tài tử Nam Bộ. Sáng hôm sau dậy sớm đi chợ nổi Cái Răng - nét văn hóa đặc sắc của vùng sông nước.', 67, 3, '2 ngày 1 đêm'),
(8, 'Tour Thái Lan 5 Ngày 4 Đêm - Khám Phá Bangkok - Pattaya', 7500000, 6490000, 'uploads/tour_thailand.png', 'Hành trình khám phá xứ sở Chùa Vàng Thái Lan. Tham quan hoàng cung tráng lệ, các ngôi chùa cổ kính linh thiêng tại Bangkok. Vui chơi giải trí tại thành phố không ngủ Pattaya và xem show diễn Alcazar hoành tráng.', 210, 4, '5 ngày 4 đêm'),
(9, 'Tour Singapore - Malaysia 6 Ngày 5 Đêm - Điểm Hẹn Đông Nam Á', 13500000, 11990000, 'uploads/tour_singapore_hagiang.png', 'Liên tuyến hai quốc gia hiện đại bậc nhất Đông Nam Á. Chiêm ngưỡng Garden by the Bay kỳ vĩ, đảo Sentosa nhộn nhịp tại Singapore. Khám phá tòa tháp đôi Petronas kiêu hãnh và động Batu kỳ bí tại Malaysia.', 175, 4, '6 ngày 5 đêm'),
(10, 'Tour Du lịch Đài Loan 5 ngày 4 đêm', 120000, 0, 'uploads/tour_taiwan.png', 'Trải nghiệm Đài Loan hiện đại cổ kính: check-in tòa nhà tháp Taipei 101, thưởng thức trà sữa chợ đêm Sĩ Lâm, thả đèn trời Thập Phần.', 95, 4, '4 ngày 3 đêm'),
(11, 'Tour Thái Lan 4 ngày 3 đêm giá rẻ', 5500000, 0, 'uploads/tour_thailand.png', 'Hành trình khám phá Bangkok - Pattaya: tham quan chùa Phật Vàng linh thiêng, dạo thuyền sông Chao Phraya, vui chơi đảo Coral.', 142, 4, '4 ngày 3 đêm'),
(12, 'Tour du lịch Sapa 3 ngày 2 đêm', 2000000, 0, 'uploads/tour_sapa.png', 'Khám phá thị trấn sương mù Sapa, check-in đỉnh Fansipan kỳ vĩ, tham quan bản Cát Cát mộc mạc và thưởng thức đặc sản núi rừng.', 118, 1, '3 ngày 2 đêm'),
(13, 'Tour Đà Lạt 2 ngày 1 đêm', 1800000, 0, 'uploads/tour_dalat.png', 'Tận hưởng không khí se lạnh mộng mơ của Đà Lạt. Tham quan vườn hoa thành phố, đồi chè Cầu Đất, Thung lũng Tình Yêu.', 85, 2, '3 ngày 2 đêm'),
(14, 'Tour Ninh Bình 3 ngày 2 đêm', 3000000, 0, 'uploads/tour_ninhbinh.png', 'Khám phá danh thắng Tràng An - di sản văn hóa và thiên nhiên thế giới, viếng chùa Bái Đính cổ kính, chiêm ngưỡng Hang Múa hùng vĩ.', 104, 1, '3 ngày 2 đêm'),
(15, 'Tour Hà Giang 5 ngày 4 đêm', 4000000, 0, 'uploads/tour_hagiang.png', 'Hành trình khám phá Hà Giang hùng vĩ với đèo Mã Pí Lèng, sông Nho Quế, Cột cờ Lũng Cú và các cánh đồng hoa tam giác mạch tuyệt đẹp.', 167, 1, '5 ngày 4 đêm'),
(16, 'TOUR MÙ CĂNG CHẢI – SUỐI GIÀNG – TÚ LỆ – MÙA LÚA CHÍN', 6500000, 5100000, 'uploads/tour_mucangchai.png', 'Trải nghiệm mùa lúa chín vàng óng ả tại thung lũng Tú Lệ, Mù Căng Chải và ngắm đồi chè Suối Giàng cổ thụ trăm năm tuổi.', 150, 1, '3 ngày 2 đêm'),
(17, 'TOUR DU LỊCH NHẬT BẢN 6 NGÀY BAY VIETNAM AIRLINES', 2500000, 2100000, 'uploads/tour_japan.png', 'Hành trình ngắm núi Phú Sĩ kỳ vĩ soi bóng xuống hồ nước bình yên và dạo bước giữa cánh đồng hoa chi anh (shibazakura) rực rỡ sắc hồng.', 120, 5, '6 ngày 5 đêm'),
(18, 'TOUR DU LỊCH HÀ GIANG MÙA HOA TAM GIÁC MẠCH 2017 3 NGÀY 2 ĐÊM', 2500000, 2100000, 'uploads/tour_singapore_hagiang.png', 'Khám phá Hà Giang hùng vĩ với đèo Mã Pí Lèng, sông Nho Quế và ngắm những cánh đồng hoa tam giác mạch lung linh trong gió mùa đông.', 180, 7, '3 ngày 2 đêm'),
(19, 'TOUR DU LỊCH CỬU TRẠI CÂU – MÂU NI CÂU – THÀNH ĐÔ 5 NGÀY 4 ĐÊM', 12500000, 1100000, 'uploads/tour_cuutraicau.png', 'Khám phá thiên đường hạ giới Cửu Trại Câu - Mâu Ni Câu với sắc thu vàng rực rỡ soi bóng xuống làn nước hồ trong vắt. Tour trọn gói 5 ngày 4 đêm dịch vụ đẳng cấp.', 120, 5, '5 ngày 4 đêm'),
(20, 'TOUR DU LỊCH ÚC 7 NGÀY BAY VIETNAM AIRLINES', 25000000, 21000000, 'uploads/tour_australia.png', 'Hành trình khám phá nước Úc xinh đẹp 7 ngày cùng hãng hàng không quốc gia Vietnam Airlines. Trải nghiệm dịch vụ 5 sao, ngắm toàn cảnh các thành phố hiện đại và thiên nhiên kỳ vĩ.', 85, 4, '7 ngày'),
(21, 'TOUR DU LỊCH CHÂU ÂU PHÁP – THỤY SỸ – Ý – VATICAN', 25000000, 21000000, 'uploads/tour_europe.png', 'Hành trình liên tuyến Châu Âu khám phá những địa danh huyền thoại tại Pháp, Thụy Sỹ, Ý và Vatican. Tận hưởng vẻ đẹp cổ kính, lãng mạn của trời Âu.', 150, 6, '7 ngày 6 đêm'),
(22, 'TOUR DU LỊCH ĐÀI LOAN BAY VIETNAM AIRLINES', 2500000, 2100000, 'uploads/tour_taiwan_new.png', 'Khám phá hòn đảo Đài Loan xinh đẹp, tham quan các ngôi chùa linh thiêng cổ kính, tượng Phật vàng khổng lồ và thưởng thức trà sữa, ẩm thực chợ đêm đặc sắc.', 95, 5, '5 ngày 4 đêm'),
(23, 'TOUR DU LỊCH HÀN QUỐC 4 NGÀY 3 ĐÊM - KHÁM PHÁ SEOUL - ĐẢO NAMI - CÔNG VIÊN EVERLAND', 12500000, 11000000, 'uploads/tour_korea.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Hàn Quốc. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Vietnam Airlines, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 50, 4, '4 ngày 3 đêm'),
(24, 'TOUR NHẬT BẢN GIÁ RẺ TRỌN GÓI 5 NGÀY - BAY VIETJET AIR', 13000000, 0, 'uploads/tour_japan.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Nhật Bản. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Vietjet Air, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 57, 4, '5 ngày 4 đêm'),
(25, 'HÀNH TRÌNH KHÁM PHÁ XỨ SỞ DUBAI - DỊCH VỤ ĐẲNG CẤP 6 NGÀY 5 ĐÊM', 14500000, 0, 'uploads/tour_dubai.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Dubai. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Bamboo Airways, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 64, 4, '6 ngày 5 đêm'),
(26, 'COMBO TOUR NGHỈ DƯỠNG PHÁP - CHECK-IN THÁP EIFFEL - BẢO TÀNG LOUVRE - CUNG ĐIỆN VERSAILLES (4 ngày 3 đêm)', 15000000, 13500000, 'uploads/tour_paris.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Pháp. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Singapore Airlines, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 71, 4, '4 ngày 3 đêm'),
(27, 'TOUR DU LỊCH MỸ (HOA KỲ) 5 NGÀY 4 ĐÊM - KHÁM PHÁ NEW YORK - WASHINGTON DC - LOS ANGELES', 16500000, 0, 'uploads/tour_usa.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Mỹ (Hoa Kỳ). Tour bao gồm trọn gói vé máy bay khứ hồi hãng Thai Airways, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 78, 4, '5 ngày 4 đêm'),
(28, 'TOUR TRUNG QUỐC GIÁ RẺ TRỌN GÓI 6 NGÀY - BAY KOREAN AIR', 17000000, 0, 'uploads/tour_china.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Trung Quốc. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Korean Air, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 85, 4, '6 ngày 5 đêm'),
(29, 'HÀNH TRÌNH KHÁM PHÁ XỨ SỞ SINGAPORE - DỊCH VỤ ĐẲNG CẤP 4 NGÀY 3 ĐÊM', 18500000, 17000000, 'uploads/tour_thailand.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Singapore. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Vietnam Airlines, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 92, 4, '4 ngày 3 đêm'),
(30, 'COMBO TOUR NGHỈ DƯỠNG THÁI LAN - CHECK-IN BANGKOK - PATTAYA - ĐẢO CORAL (5 ngày 4 đêm)', 19000000, 0, 'uploads/tour_thailand.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Thái Lan. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Vietjet Air, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 99, 4, '5 ngày 4 đêm'),
(31, 'TOUR DU LỊCH ÚC 6 NGÀY 5 ĐÊM - KHÁM PHÁ SYDNEY OPERA HOUSE - BLUE MOUNTAINS - MELBOURNE', 20500000, 0, 'uploads/tour_australia.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Úc. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Bamboo Airways, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 106, 4, '6 ngày 5 đêm'),
(32, 'TOUR CHÂU ÂU GIÁ RẺ TRỌN GÓI 4 NGÀY - BAY SINGAPORE AIRLINES', 21000000, 19500000, 'uploads/tour_europe.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Châu Âu. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Singapore Airlines, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 113, 4, '4 ngày 3 đêm'),
(33, 'HÀNH TRÌNH KHÁM PHÁ XỨ SỞ ĐÀI LOAN - DỊCH VỤ ĐẲNG CẤP 5 NGÀY 4 ĐÊM', 22500000, 0, 'uploads/tour_taiwan_new.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Đài Loan. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Thai Airways, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 120, 4, '5 ngày 4 đêm'),
(34, 'COMBO TOUR NGHỈ DƯỠNG CỬU TRẠI CÂU - CHECK-IN MÂU NI CÂU - THÀNH ĐÔ - LẠC SƠN ĐẠI PHẬT (6 ngày 5 đêm)', 23000000, 0, 'uploads/tour_cuutraicau.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Cửu Trại Câu. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Korean Air, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 127, 4, '6 ngày 5 đêm'),
(35, 'TOUR DU LỊCH HÀN QUỐC 4 NGÀY 3 ĐÊM - KHÁM PHÁ SEOUL - ĐẢO NAMI - CÔNG VIÊN EVERLAND', 24500000, 23000000, 'uploads/tour_korea.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Hàn Quốc. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Vietnam Airlines, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 134, 4, '4 ngày 3 đêm'),
(36, 'TOUR NHẬT BẢN GIÁ RẺ TRỌN GÓI 5 NGÀY - BAY VIETJET AIR', 25000000, 0, 'uploads/tour_japan.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Nhật Bản. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Vietjet Air, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 141, 4, '5 ngày 4 đêm'),
(37, 'HÀNH TRÌNH KHÁM PHÁ XỨ SỞ DUBAI - DỊCH VỤ ĐẲNG CẤP 6 NGÀY 5 ĐÊM', 26500000, 0, 'uploads/tour_dubai.png', 'Khám phá vẻ đẹp kỳ vĩ và những nét văn hóa đặc sắc tại Dubai. Tour bao gồm trọn gói vé máy bay khứ hồi hãng Bamboo Airways, khách sạn tiêu chuẩn 4-5 sao, các bữa ăn đặc sản địa phương và hướng dẫn viên suốt tuyến tận tâm nhiệt tình.', 148, 4, '6 ngày 5 đêm'),
