(92, 'Tour du lịch châu âu: đức – hà lan – bỉ - luxembourg pháp', 68900000, 60900000, 'uploads/tour_europe1.png', 'Khám phá vẻ đẹp cổ kính của các thành phố hàng đầu Châu Âu: Cologne (Đức), Amsterdam (Hà Lan), Brussels (Bỉ) và Paris (Pháp). Tour trọn gói cao cấp.', 150, 6, '8N7Đ'),
(93, 'Tour châu âu: ý - vatican - thụy sỹ - pháp', 99900000, 89900000, 'uploads/tour_europe2.png', 'Hành trình di sản đi qua tháp nghiêng Pisa, tòa thánh Vatican kiêu sa, dãy Alps Thụy Sỹ phủ đầy tuyết và thủ đô ánh sáng Paris lãng mạn.', 180, 6, '13N12Đ'),
(94, 'Tour châu âu: thổ nhĩ kỳ 10 ngày 9 đêm', 37900000, 35900000, 'uploads/tour_europe3.png', 'Khám phá xứ sở thảm bay kỳ diệu Thổ Nhĩ Kỳ. Tham quan thánh đường xanh Blue Mosque, bay khinh khí cầu ngắm thung lũng Cappadocia hùng vĩ.', 140, 6, '10N9Đ'),
(95, 'Tour du lịch châu âu: đức - pháp - thụy sỹ - ý', 75900000, 69900000, 'uploads/tour_europe4.png', 'Liên tuyến 4 quốc gia trung tâm Châu Âu. Chiêm ngưỡng tháp Eiffel, chinh phục núi tuyết Titlis và dạo thuyền lãng mạn tại Venice.', 160, 6, '11N10Đ'),
(96, 'Tour châu âu du lịch: đức - áo - ý - thụy sỹ', 75900000, 71900000, 'uploads/tour_europe5.png', 'Hành trình tuyệt mỹ đi qua các thành phố âm nhạc và cổ tích. Khám phá vẻ đẹp yên bình của Hallstatt và thị trấn Lucerne quyến rũ.', 130, 6, '11N10Đ'),
(97, 'Tour châu âu 5 nước: pháp - bỉ - hà lan - đức - luxembourg', 65900000, 61900000, 'uploads/tour_europe6.png', 'Khám phá trái tim Châu Âu qua 5 quốc gia phát triển bậc nhất. Tham quan cung điện Versailles, Grand Place Brussels và làng cổ Giethoorn.', 195, 6, '10N9Đ'),
(98, 'Tour du lịch châu âu: pháp - bỉ - hà lan', 59900000, 57900000, 'uploads/tour_europe7.png', 'Tour ngắn ngày lý tưởng khám phá Tây Âu cổ kính. Đi thuyền trên kênh đào Amsterdam, check-in tượng chú bé đứng tè Manneken Pis.', 110, 6, '11N10Đ'),
(99, 'Tour đông âu: đức - séc - áo - hungary', 66900000, 62900000, 'uploads/tour_europe8.png', 'Chiêm ngưỡng vẻ đẹp lộng lẫy và bí ẩn của Đông Âu. Khám phá lâu đài cổ Prague, cung điện Schonbrunn Vienna và hoàng hôn trên sông Danube.', 125, 6, '10N9Đ'),
(100, 'Tour du lịch Nam Ninh Cổ Trấn 4 ngày 3 đêm', 7000000, 5900000, 'uploads/tour_china.png', 'Khám phá Nam Ninh Cổ Trấn thanh bình thơ mộng với những ngôi nhà cổ soi bóng xuống dòng sông. Hành trình khám phá ẩm thực Trung Hoa đặc sắc.', 95, 5, '4N3Đ'),
(101, 'Tour Hà Khẩu Bình Biên 3 ngày 2 đêm', 4100000, 3990000, 'uploads/tour_taiwan.png', 'Hành trình check-in Hà Khẩu nhộn nhịp, khám phá Bình Biên với công viên rừng nguyên sinh và những cây cầu gỗ treo tuyệt đẹp bên thác nước.', 85, 5, '3N2Đ'),
(102, 'Tour du lịch singapore - malaysia 5 ngày 4 đêm', 15990000, 12990000, 'uploads/tour_singapore_hagiang.png', 'Liên tuyến hai quốc gia hiện đại Đông Nam Á: check-in tượng sư tử biển Merlion, đảo Sentosa Singapore và tháp đôi Petronas Malaysia.', 160, 5, '5N4Đ'),
(103, 'Tour du lịch hà nội singapore 5 ngày 4 đêm', 17590000, 14990000, 'uploads/tour_thailand.png', 'Khám phá Singapore - thành phố xanh sạch nhất thế giới. Trải nghiệm dịch vụ bay Vietnam Airlines sang trọng, nghỉ dưỡng khách sạn 4 sao.', 140, 5, '5N4Đ'),
(104, 'Tour nhật bản: hà nội – tokyo – phú sĩ 5 ngày 4 đêm', 25900000, 22900000, 'uploads/tour_japan.png', 'Hành trình ngắm núi Phú Sĩ tuyết phủ trắng xóa, tham quan chùa cổ Asakusa và khám phá thủ đô Tokyo hiện đại, náo nhiệt.', 210, 5, '5N4Đ'),
(105, 'Tour du lịch nhật bản: hà nội – osaka – kyoto', 38900000, 36900000, 'uploads/tour_japan.png', 'Khám phá cố đô cổ kính Kyoto, check-in lâu đài cổ Osaka huyền thoại và thưởng thức các món ăn truyền thống đặc sắc của xứ Phù Tang.', 135, 5, '6N5Đ'),
(106, 'Tour du lịch nhật bản: nagoya – tokyo – hakone', 35900000, 29500000, 'uploads/tour_japan.png', 'Hành trình vàng khám phá Nhật Bản. Tắm suối nước nóng Onsen truyền thống tại Hakone, ngắm núi Phú Sĩ hùng vĩ từ hồ Ashi.', 180, 5, '6N5Đ'),
(107, 'Tour khám phá Tokyo mùa lá đỏ 5 ngày 4 đêm', 27900000, 24900000, 'uploads/tour_korea.png', 'Khám phá thủ đô Tokyo rực rỡ sắc đỏ vàng của mùa lá rụng. Trải nghiệm ẩm thực và mua sắm thú vị tại Shinjuku, Shibuya.', 95, 5, '5N4Đ'),
(108, 'Tour Nhật Bản cung đường vàng Tokyo - Kyoto - Osaka', 32900000, 29900000, 'uploads/tour_taiwan_new.png', 'Hành trình huyền thoại kết nối ba thành phố lớn nhất Nhật Bản. Trải nghiệm tàu siêu tốc Shinkansen hiện đại.', 125, 5, '6N5Đ'),
(109, 'Tour du lịch hokkaido tuyết trắng rơi 6 ngày', 42900000, 38900000, 'uploads/tour_china.png', 'Khám phá thiên đường tuyết trắng Hokkaido phía Bắc Nhật Bản. Tham gia lễ hội băng tuyết Otaru kỳ ảo.', 80, 5, '6N5Đ'),
(110, 'Tour mùa hoa anh đào nở rộ Tokyo - Fuji 5 ngày', 26900000, 23900000, 'uploads/tour_singapore_hagiang.png', 'Đắm chìm trong sắc hồng lãng mạn của hoa anh đào quanh núi Phú Sĩ. Trải nghiệm tắm Onsen thư giãn tuyệt đối.', 140, 5, '5N4Đ'),
(111, 'Tour du lịch Osaka - Kobe - Nara 5 ngày 4 đêm', 28900000, 25900000, 'uploads/tour_thailand.png', 'Khám phá vùng Kansai cổ kính. Vui chơi cùng những chú nai thân thiện tại công viên Nara, thưởng thức thịt bò Kobe trứ danh.', 110, 5, '5N4Đ'),
(112, 'Tour khám phá Nagoya và thung lũng Shirakawago', 34900000, 31900000, 'uploads/tour_europe.png', 'Ghé thăm ngôi làng cổ tích Shirakawago với kiến trúc mái nhà dốc đứng độc đáo, phủ đầy tuyết trắng vào mùa đông.', 90, 5, '6N5Đ'),
(113, 'Tour Nhật Bản trọn gói bay Bamboo Airways 5 ngày', 23900000, 21900000, 'uploads/tour_dubai.png', 'Tour giá tốt dịch vụ bay Bamboo Airways đẳng cấp. Khám phá trọn vẹn thủ đô Tokyo và thung lũng Owakudani.', 150, 5, '5N4Đ'),
(114, 'Tour nghỉ dưỡng suối nước nóng Onsen Hakone 4 ngày', 19900000, 17900000, 'uploads/tour_paris.png', 'Chuyến đi nghỉ dưỡng phục hồi sức khỏe hoàn hảo tại Hakone. Tận hưởng nguồn suối khoáng nóng tự nhiên chất lượng.', 75, 5, '4N3Đ'),
(115, 'Tour du thuyền ngắm vịnh Matsushima Nhật Bản', 31900000, 28900000, 'uploads/tour_usa.png', 'Chiêm ngưỡng một trong ba danh lam thắng cảnh đẹp nhất Nhật Bản từ du thuyền. Khám phá văn hóa vùng Sendai.', 85, 5, '5N4Đ'),
(116, 'Tour hành hương các ngôi chùa cổ Kyoto 5 ngày', 24900000, 22900000, 'uploads/tour_australia.png', 'Tìm lại sự thanh tịnh tại cố đô cổ kính. Tham quan Chùa Vàng Kinkaku-ji, chùa Thanh Thủy Kiyomizu-dera linh thiêng.', 105, 5, '5N4Đ'),
(117, 'Tour trekking ngắm cảnh núi Phú Sĩ hùng vĩ 4 ngày', 21900000, 19900000, 'uploads/tour_mucangchai.png', 'Thử thách leo núi trekking và lưu lại những khoảnh khắc tuyệt đẹp của ngọn núi biểu tượng đất nước mặt trời mọc.', 65, 5, '4N3Đ'),
(118, 'Tour Nhật Bản mùa thu lá vàng lá đỏ Osaka 5 ngày', 25900000, 23500000, 'uploads/tour_ninhbinh.png', 'Khám phá lâu đài Osaka lộng lẫy chìm trong sắc lá phong đỏ rực rỡ của mùa thu Kansai yên bình.', 135, 5, '5N4Đ'),
(119, 'Tour du lịch Okinawa đảo ngọc Nhật Bản 5 ngày', 29900000, 26900000, 'uploads/tour_sapa.png', 'Tận hưởng làn nước biển xanh ngọc bích, cát trắng mịn màng và văn hóa độc đáo Ryukyu tại đảo ngọc Okinawa.', 115, 5, '5N4Đ'),
(120, 'Tour trải nghiệm hái hoa quả tại vườn trái cây Yamanashi', 22900000, 20900000, 'uploads/tour_dalat.png', 'Trải nghiệm tự tay hái và thưởng thức nho mẫu đơn, đào tươi mọng nước ngay tại vườn trái cây Yamanashi nổi tiếng.', 95, 5, '5N4Đ'),
(121, 'Tour lễ hội hoa Lavender hồ Kawaguchiko 5 ngày', 26500000, 24500000, 'uploads/tour_hagiang.png', 'Ngắm nhìn cánh đồng hoa oải hương tím ngắt soi bóng bên hồ Kawaguchiko dưới chân núi Phú Sĩ tuyệt đẹp.', 100, 5, '5N4Đ'),
(122, 'Tour du lịch Nhật Bản mùa đông trượt tuyết Niigata 5 ngày', 28900000, 26500000, 'uploads/tour_japan.png', 'Trải nghiệm các trò chơi tuyết thú vị và học trượt tuyết tại khu nghỉ dưỡng nổi tiếng tuyết dày bậc nhất Niigata.', 120, 5, '5N4Đ'),
(123, 'Tour du lịch Tràng An – Ninh Bình 2 ngày 1 đêm', 2500000, 1990000, 'uploads/tour_trangan.png', 'Khám phá khu du lịch sinh thái Tràng An với hàng chục hang động nước kỳ vĩ, viếng đền cổ và thưởng thức đặc sản cơm cháy dê núi Ninh Bình.', 110, 1, '2N1Đ'),
(124, 'Tour du lịch Quy Nhơn – Kỳ Co – Eo Gió 3 ngày 2 đêm', 4200000, 3500000, 'uploads/tour_quynhon.png', 'Đắm mình trong làn nước biển trong xanh như ngọc bích tại bãi tắm Kỳ Co, chiêm ngưỡng Eo Gió hùng vĩ đón hoàng hôn buông lộng gió.', 140, 2, '3N2Đ'),
(125, 'Tour du lịch khám phá di sản Động Phong Nha – Kẻ Bàng', 3000000, 2600000, 'uploads/tour_phongnha.png', 'Hành trình chinh phục động nước Phong Nha lung linh thạch nhũ và thám hiểm vườn quốc gia Phong Nha Kẻ Bàng – Di sản thiên nhiên thế giới.', 95, 2, '2 ngày'),
(126, 'Tour du lịch Huế cổ kính – Khám phá Cố đô Đại Nội 1 ngày', 1200000, 990000, 'uploads/tour_hue.png', 'Tham quan Đại Nội Huế cổ kính linh thiêng, viếng chùa Thiên Mụ hơn 400 năm tuổi và lăng Khải Định với kiến trúc nghệ thuật khảm sành sứ độc đáo.', 150, 2, '1 ngày'),
(127, 'Tour du lịch Nha Trang – Vinwonders – Vịnh San Hô 4 ngày 3 đêm', 4500000, 3990000, 'uploads/tour_nhatrang1.png', 'Trải nghiệm cáp treo vượt biển Nha Trang, vui chơi thả ga tại Vinwonders và lặn ngắm san hô nhiều màu sắc tại Vịnh San Hô tuyệt đẹp.', 160, 2, '4N3Đ'),
(128, 'Tour du lịch biển Nha Trang – Hòn Mun – Hòn Tằm 3 ngày 2 đêm', 3500000, 2990000, 'uploads/tour_nhatrang2.png', 'Khám phá thiên đường san hô Hòn Mun, thư giãn tắm bùn và các hoạt động thể thao biển hấp dẫn tại đảo Hòn Tằm xanh mát.', 110, 2, '3N2Đ'),
(129, 'Tour Nha Trang – Điệp Sơn – Dốc Lết 4 ngày 3 đêm', 3900000, 3400000, 'uploads/tour_nhatrang3.png', 'Trải nghiệm đi bộ trên con đường giữa biển độc nhất vô nhị tại đảo Điệp Sơn và tắm biển Dốc Lết cát trắng mịn màng.', 90, 2, '4N3Đ'),
(130, 'Tour Đà Nẵng – Bà Nà Hills – Ngũ Hành Sơn 3 ngày 2 đêm', 3200000, 2790000, 'uploads/tour_danang1.png', 'Check-in Cầu Vàng nổi tiếng thế giới tại Bà Nà Hills, tham quan Ngũ Hành Sơn huyền thoại và dạo bước phố cổ Hội An rực rỡ đèn lồng.', 140, 2, '3N2Đ'),
(131, 'Tour du lịch Sapa – Cát Cát – Fansipan 2 ngày 1 đêm', 2500000, 1990000, 'uploads/tour_sapa1.png', 'Chinh phục nóc nhà Đông Dương Fansipan bằng cáp treo hiện đại, thăm bản Cát Cát của người H\'Mông đen mộc mạc yên bình.', 112, 1, '2N1Đ'),
(132, 'Tour du lịch Hạ Long – Ngủ đêm du thuyền 5 sao đẳng cấp', 4800000, 3990000, 'uploads/tour_halong1.png', 'Trải nghiệm dịch vụ nghỉ dưỡng thượng lưu trên du thuyền Hạ Long 5 sao, tham quan Hang Sửng Sốt, Đảo Ti Tốp và chèo thuyền kayak.', 150, 1, '2N1Đ'),
(133, 'Tour Phú Quốc – Bãi Sao – Cáp treo Hòn Thơm 4 ngày 3 đêm', 5200000, 4790000, 'uploads/tour_phuquoc1.png', 'Tận hưởng làn nước mát lành tại Bãi Sao Phú Quốc, trải nghiệm cáp treo vượt biển dài nhất thế giới sang đảo Hòn Thơm vui chơi giải trí.', 130, 3, '4N3Đ'),
(134, 'Tour du lịch Miền Tây – Cần Thơ – Chợ nổi Cái Răng', 1900000, 1490000, 'uploads/tour_mientay1.png', 'Khám phá nét văn hóa sông nước đặc trưng của Miền Tây Nam Bộ, đi thuyền tham quan chợ nổi Cái Răng nhộn nhịp từ sáng sớm.', 80, 3, '2N1Đ'),
(135, 'Tour du lịch Hà Giang – Quản Bạ – Yên Minh – Đồng Văn', 3800000, 3200000, 'uploads/tour_hagiang1.png', 'Hành trình chinh phục cao nguyên đá Đồng Văn hùng vĩ, tham quan cổng trời Quản Bạ, dốc Thẩm Mã và đèo Mã Pí Lèng huyền thoại.', 175, 1, '3N2Đ'),
(136, 'Tour du lịch Ninh Bình – Bái Đính – Tràng An 1 ngày giá rẻ', 990000, 790000, 'uploads/tour_ninhbinh1.png', 'Hành trình chiêm bái ngôi chùa Bái Đính lớn nhất Đông Nam Á, ngồi thuyền khám phá danh thắng Tràng An non nước hữu tình.', 105, 1, '1 ngày'),
(137, 'Tour du lịch Huế – Thánh địa La Vang – Động Phong Nha', 2800000, 2400000, 'uploads/tour_hue1.png', 'Hành trình kết nối di sản miền Trung: tham quan cố đô Huế, viếng Thánh địa La Vang linh thiêng và thám hiểm động nước Phong Nha.', 95, 2, '2N1Đ'),
(138, 'Tour Nha Trang – Tắm bùn khoáng nóng – Tháp Bà Ponagar', 1500000, 1290000, 'uploads/tour_nhatrang4.png', 'Thư giãn tắm bùn khoáng nóng thiên nhiên phục hồi sức khỏe, viếng cụm tháp cổ Ponagar - di sản kiến trúc Chăm Pa cổ kính.', 85, 2, '1 ngày'),
(139, 'Tour du lịch Nha Trang – Bình Ba hoang sơ 2 ngày 1 đêm', 2200000, 1990000, 'uploads/tour_nhatrang5.png', 'Khám phá đảo tôm hùm Bình Ba hoang sơ xinh đẹp, thưởng thức tiệc hải sản tươi ngon đầm ấm bên bãi biển lộng gió.', 115, 2, '2N1Đ'),
(140, 'Tour Nha Trang khánh hòa – Đảo Khỉ – Suối Hoa Lan 1 ngày', 900000, 750000, 'uploads/tour_nhatrang6.png', 'Vui chơi cùng hàng trăm chú khỉ tinh nghịch tại đảo khỉ, trekking ngắm cảnh hoa lan rực rỡ sắc màu tại khu du lịch sinh thái suối Hoa Lan.', 65, 2, '1 ngày'),
(141, 'Tour Đà Lạt – Thành phố ngàn hoa mộng mơ 4 ngày 3 đêm', 3100000, 2690000, 'uploads/tour_dalat1.png', 'Ghé thăm Thung lũng Tình Yêu, đồi chè Cầu Đất xanh mát, chùa Linh Phước kỳ vĩ và tận hưởng khí hậu mát mẻ quanh năm tại Đà Lạt.', 125, 2, '4N3Đ'),
(142, 'Tour Côn Đảo linh thiêng – Viếng mộ anh hùng Võ Thị Sáu', 4900000, 4200000, 'uploads/tour_condao1.png', 'Hành trình tâm linh viếng nghĩa trang Hàng Dương, mộ chị Võ Thị Sáu linh thiêng lúc nửa đêm và tham quan nhà tù Côn Đảo di tích lịch sử.', 105, 3, '3N2Đ'),
(143, 'Tour du lịch Phan Thiết – Mũi Né cát trắng nắng vàng', 2400000, 1990000, 'uploads/tour_muine1.png', 'Check-in đồi cát bay Mũi Né tuyệt đẹp, tham quan Suối Tiên mộng mơ, lâu đài rượu vang và tắm biển Mũi Né cát trắng trải dài.', 110, 3, '2N1Đ'),
(144, 'Tour Quy Nhơn – Ghềnh Ráng Tiên Sa – Tháp Bánh Ít 3 ngày', 3600000, 3100000, 'uploads/tour_quynhon1.png', 'Khám phá khu du lịch Ghềnh Ráng Tiên Sa, viếng mộ nhà thơ Hàn Mặc Tử và tham quan quần thể tháp Bánh Ít kiến trúc cổ kính Cham-pa.', 115, 2, '3N2Đ'),
(145, 'Tour du lịch Đông Âu: Đức - Séc - Áo - Slovakia - Hungary', 68900000, 60900000, 'uploads/tour_dongau1.png', 'Trải nghiệm hành trình tuyệt đẹp đi qua các quốc gia Đông Âu cổ kính. Khám phá tháp truyền hình Berlin, lâu đài Prague nguy nga và dòng sông Danube thơ mộng.', 120, 6, '10N9Đ'),
(146, 'Tour khám phá Đông Âu: Pháp - Đức - Ba Lan - Séc', 75900000, 69900000, 'uploads/tour_dongau2.png', 'Hành trình liên tuyến khám phá lịch sử và văn hóa độc đáo vùng Đông Âu. Tham quan các di sản thế giới UNESCO tại Warsaw, Krakow và Prague cổ kính.', 130, 6, '11N10Đ'),
(147, 'Tour Đông Âu mùa thu vàng: Áo - Hungary - Séc - Đức', 75900000, 71900000, 'uploads/tour_dongau3.png', 'Đắm chìm trong sắc vàng lãng mạn của mùa thu Đông Âu. Chiêm ngưỡng vẻ đẹp cổ tích của thị trấn Hallstatt, hoàng cung Schonbrunn và lâu đài Budapest.', 140, 6, '11N10Đ'),
(148, 'Tour liên tuyến Đông Âu cổ kính: Đức - Ba Lan - Séc', 65900000, 61900000, 'uploads/tour_dongau4.png', 'Khám phá trái tim Đông Âu qua những điểm đến đậm chất lịch sử. Tour trọn gói cao cấp bao gồm vé máy bay, khách sạn 4 sao và các bữa ăn đặc sản địa phương.', 115, 6, '10N9Đ'),
(149, 'Tour du lịch Đông Âu lễ hội: Áo - Séc - Hungary', 59900000, 57900000, 'uploads/tour_dongau5.png', 'Hòa mình vào không khí lễ hội rực rỡ và mua sắm tại các chợ truyền thống Đông Âu. Thưởng thức âm nhạc cổ điển Vienna và ẩm thực đặc sắc Goulash.', 125, 6, '11N10Đ'),
(150, 'Tour Đông Âu huyền bí: Hungary - Slovakia - Séc', 66900000, 62900000, 'uploads/tour_dongau6.png', 'Hành trình khám phá những nét đẹp tiềm ẩn của Trung và Đông Âu. Chiêm ngưỡng lâu đài Bratislava, cầu đá Charles và tòa nghị viện Budapest tráng lệ.', 110, 6, '10N9Đ'),
(151, 'Tour di sản Đông Âu: Đức - Séc - Áo - Hungary', 69900000, 64900000, 'uploads/tour_dongau7.png', 'Hành trình khám phá các di sản văn hóa thế giới nổi tiếng nhất khu vực Đông Âu. Dạo thuyền ngắm hoàng hôn trên sông Danube thơ mộng và yên bình.', 135, 6, '11N10Đ'),
(152, 'Tour nghỉ dưỡng Đông Âu: Áo - Séc - Hungary', 72900000, 67900000, 'uploads/tour_dongau8.png', 'Kỳ nghỉ dưỡng tuyệt vời tại các thành phố lãng mạn nhất Châu Âu. Trải nghiệm dịch vụ đẳng cấp, hướng dẫn viên chuyên nghiệp suốt tuyến tận tâm.', 145, 6, '10N9Đ'),
(153, 'Tour du lịch Trung Âu: Đức - Séc - Áo - Hungary', 68900000, 60900000, 'uploads/tour_trungau1.png', 'Khám phá vẻ đẹp lịch sử và phong cảnh thiên nhiên tuyệt mỹ vùng Trung Âu. Hành trình lý tưởng đi qua các thành phố cổ kính và lãng mạn nhất.', 120, 6, '10N9Đ'),
(154, 'Tour châu âu: ý - vatican - thụy sỹ - pháp - đức (Trung Âu)', 99900000, 89900000, 'uploads/tour_trungau2.png', 'Hành trình khám phá các nước Trung và Tây Âu. Trải nghiệm dịch vụ đẳng cấp, tham quan các địa danh lịch sử nổi tiếng nhất thế giới.', 180, 6, '13N12Đ'),
(155, 'Tour khám phá Trung Âu: Thổ Nhĩ Kỳ - Hy Lạp 10 ngày', 37900000, 35900000, 'uploads/tour_trungau3.png', 'Khám phá vùng đất huyền thoại giao thoa văn hóa Á - Âu. Trải nghiệm bay khinh khí cầu tại Cappadocia và ngắm hoàng hôn trên đảo Santorini.', 140, 6, '10N9Đ'),
(156, 'Tour du lịch châu âu: đức - pháp - thụy sỹ - ý (Trung Âu)', 75900000, 69900000, 'uploads/tour_trungau4.png', 'Hành trình tuyệt vời qua những quốc gia trái tim của Châu Âu. Chiêm ngưỡng vẻ đẹp cổ kính, lãng mạn và hiện đại đan xen.', 160, 6, '11N10Đ'),
(157, 'Tour châu âu du lịch: đức - áo - ý - thụy sỹ (Trung Âu)', 75900000, 71900000, 'uploads/tour_trungau5.png', 'Khám phá cung đường vàng Trung Âu thơ mộng. Thưởng ngoạn cảnh sắc dãy Alps phủ tuyết trắng và các thị trấn cổ bình yên.', 130, 6, '11N10Đ'),
(158, 'Tour châu âu 5 nước: pháp - bỉ - hà lan - đức - luxembourg (Trung Âu)', 65900000, 61900000, 'uploads/tour_trungau6.png', 'Hành trình khám phá nét đẹp cổ điển và hiện đại tại 5 quốc gia phát triển bậc nhất Châu Âu. Dịch vụ bay Vietnam Airlines cao cấp.', 195, 6, '10N9Đ'),
(159, 'Tour du lịch châu âu: pháp - bỉ - hà lan (Trung Âu)', 59900000, 57900000, 'uploads/tour_trungau7.png', 'Chuyến du lịch khám phá Tây và Trung Âu thơ mộng. Thích hợp cho gia đình nghỉ dưỡng và lưu giữ những khoảnh khắc tuyệt đẹp.', 110, 6, '11N10Đ'),
(160, 'Tour liên tuyến Trung Âu: đức - séc - áo - hungary', 66900000, 62900000, 'uploads/tour_trungau8.png', 'Chiêm ngưỡng vẻ đẹp cổ kính và lộng lẫy của các nước Trung Âu. Tham quan lâu đài cổ Prague và dạo thuyền lãng mạn trên dòng sông Danube.', 125, 6, '10N9Đ'),
(161, 'Du lịch Hè - Tour Đà Nẵng - Bà Nà Hills - Hội An 3 ngày 2 đêm', 9850000, 8900000, 'uploads/tour_danang_he.png', 'Hành trình du lịch hè tuyệt vời tại Đà Nẵng, tham quan Bà Nà Hills và phố cổ Hội An.', 150, 2, '3N2Đ');
