INSERT INTO `tintuc` (`id`, `title`, `image`, `description`, `date`) VALUES
(1, 'Kinh nghiệm Phượt Tây Bắc mùa Đông', 'uploads/news1.png', 'Sà bài đi!!! Việt Anh vừa kết thúc chuyến du lịch Lào tự túc trong 10 ngày, và giờ mình đang rất háo hức chia sẻ lại những kỷ niệm đẹp trong chuyến đi...', '02 Th11'),
(2, 'Kinh nghiệm check-in Đà Lạt mùa đông', 'uploads/news2.png', 'Sà bài đi!!! Việt Anh vừa kết thúc chuyến du lịch Lào tự túc trong 10 ngày, và giờ mình đang rất háo hức chia sẻ lại những kỷ niệm đẹp trong chuyến đi...', '05 Th11'),
(3, 'Kinh nghiệm du lịch tự túc Sapa 3 ngày 2 đêm', 'uploads/news3.png', 'Sà bài đi!!! Việt Anh vừa kết thúc chuyến du lịch Lào tự túc trong 10 ngày, và giờ mình đang rất háo hức chia sẻ lại những kỷ niệm đẹp trong chuyến đi...', '10 Th11'),
(4, 'Chia sẻ kinh nghiệm du lịch Luang Prabang tự túc', 'uploads/news4.png', 'Sà bài đi!!! Việt Anh vừa kết thúc chuyến du lịch Lào tự túc trong 10 ngày, và giờ mình đang rất háo hức chia sẻ lại những kỷ niệm đẹp trong chuyến đi...', '12 Th11'),
(5, 'Du lịch Đà Lạt – đừng quên ghé check-in đồi chè Cầu Đất', 'uploads/news5.png', 'Ai ai từng một lần đến du lịch Đà Lạt đều chẳng thể bỏ qua việc ghé...', '15 Th11'),
(6, 'Hành trình khám phá Hà Giang hùng vĩ qua những cung đèo', 'uploads/news6.png', 'Cùng xách ba lô lên đi khám phá vẻ đẹp kỳ vĩ của cao nguyên đá Đồng Văn Hà Giang, ngắm hoa tam giác mạch và trải nghiệm văn hóa độc đáo...', '18 Th11'),
(7, 'Kinh nghiệm du lịch Vịnh Hạ Long trọn gói 2 ngày 1 đêm', 'uploads/news7.png', 'Chia sẻ cẩm nang chi tiết nhất về kỳ nghỉ dưỡng đẳng cấp trên du thuyền Hạ Long 5 sao, các hoạt động chèo kayak và khám phá hang động...', '20 Th11'),
(8, 'Top 10 địa danh check-in cực hot tại Phú Quốc không thể bỏ lỡ', 'uploads/news8.png', 'Phú Quốc không chỉ nổi tiếng với biển xanh cát trắng, mà còn thu hút giới trẻ bởi những tọa độ sống ảo triệu like cực sang chảnh...', '22 Th11'),
(9, 'Ăn gì ở Đà Nẵng? Cẩm nang ẩm thực miền Trung siêu chi tiết', 'uploads/news9.png', 'Đà Nẵng không chỉ là thành phố đáng sống mà còn là thiên đường ẩm thực miền Trung với bánh tráng cuốn thịt heo, mì Quảng, chả bò...', '25 Th11'),
(10, 'Khám phá vẻ đẹp cổ kính bình yên của Phố Cổ Hội An', 'uploads/news10.png', 'Dạo bước dưới những ánh đèn lồng rực rỡ sắc màu, chiêm ngưỡng những ngôi nhà tường vàng mái ngói rêu phong tại Phố Cổ Hội An lãng mạn...', '28 Th11'),
(11, 'Trekking Mù Căng Chải ngắm mùa lúa chín vàng óng ả', 'uploads/news11.png', 'Khám phá vẻ đẹp ngoạn mục của những thửa ruộng bậc thang kỳ vĩ nhất Việt Nam, lưu giữ những khung cảnh lúa chín óng vàng lấp lánh...', '01 Th12'),
(12, 'Chia sẻ lịch trình du lịch tự túc Nha Trang cực kỳ tiết kiệm', 'uploads/news12.png', 'Bật mí chi phí và các mẹo đặt phòng khách sạn, thuê xe máy và tour đảo giá rẻ khi đi du lịch Nha Trang tự túc cùng nhóm bạn thân...', '03 Th12'),
(13, 'Kinh nghiệm đi tour du lịch Cửu Trại Câu Trung Quốc từ A đến Z', 'uploads/news13.png', 'Khám phá thiên đường hạ giới Cửu Trại Câu với những hồ nước ngũ sắc trong vắt phản chiếu núi rừng và những ngọn thác hùng vĩ kỳ ảo...', '05 Th12'),
(14, 'Du lịch tự túc Tokyo Nhật Bản: Đi lại, ăn uống và vui chơi', 'uploads/news14.png', 'Cẩm nang hướng dẫn đầy đủ từ việc xin visa, mua thẻ tàu JR Pass đến các điểm tham quan hot nhất tại thủ đô Tokyo sầm uất...', '08 Th12'),
(15, 'Trải nghiệm hành trình khám phá Châu Âu cổ kính qua 3 quốc gia', 'uploads/news15.png', 'Liên tuyến du lịch Đức - Pháp - Thụy Sỹ ngắm nhìn những tòa lâu đài cổ, leo đỉnh núi tuyết Titlis hùng vĩ và dạo phố cổ lãng mạn...', '10 Th12'),
(16, 'Du lịch tự túc Đài Loan: Mua sắm thả ga tại chợ đêm Sĩ Lâm', 'uploads/news16.png', 'Đến với Đài Loan, đừng bỏ lỡ cơ hội thưởng thức trà sữa trân châu truyền thống, đậu phụ thối và mua sắm thỏa thích tại các chợ đêm...', '12 Th12'),
(17, 'Khám phá đảo ngọc Cát Bà hoang sơ và kỳ vĩ miền Bắc', 'uploads/news17.png', 'Trải nghiệm chèo thuyền kayak trên vịnh Lan Hạ, trekking vườn quốc gia Cát Bà hoang dã và tận hưởng kỳ nghỉ yên bình bên biển xanh...', '15 Th12'),
(18, 'Lịch trình phượt Cao Nguyên Đá Đồng Văn bằng xe máy 3 ngày', 'uploads/news18.png', 'Hành trình chinh phục cực Bắc tổ quốc bằng xe máy qua dốc Thẩm Mã, cổng trời Quản Bạ, đèo Mã Pí Lèng huyền thoại đầy phấn khích...', '18 Th12'),
(19, 'Kinh nghiệm du lịch tâm linh chùa Bái Đính Ninh Bình đầu năm', 'uploads/news19.png', 'Hướng dẫn chi tiết lịch trình chiêm bái ngôi chùa lớn nhất Đông Nam Á, kết hợp ngồi thuyền khám phá danh thắng Tràng An non nước...', '22 Th12'),
(20, 'Du lịch tự túc Singapore tiết kiệm chi phí tham quan', 'uploads/news20.png', 'Cách săn vé máy bay giá rẻ, lưu trú homestay và tận hưởng các địa điểm tham quan miễn phí cực kỳ nổi tiếng tại quốc đảo sư tử...', '25 Th12'),
(21, 'Kinh nghiệm khám phá cố đô Huế mộng mơ và cổ kính', 'uploads/news21.png', 'Tham quan Đại Nội cổ kính linh thiêng, viếng lăng tẩm các vị vua triều Nguyễn và thưởng thức trà cung đình Huế đượm vị thơm nồng...', '28 Th12'),
(22, 'Phượt Mũi Né Phan Thiết ngắm đồi cát bay lộng gió', 'uploads/news22.png', 'Check-in đồi cát trắng, đồi cát đỏ kỳ thú tại Phan Thiết, trải nghiệm đua xe địa hình vượt cát và ngắm hoàng hôn buông lãng mạn...', '30 Th12'),
(23, 'Cẩm nang du lịch Miền Tây sông nước: Cần Thơ - Bến Tre', 'uploads/news23.png', 'Trải nghiệm nét văn hóa chợ nổi Cái Răng từ sáng sớm, dạo vườn trái cây trĩu quả và nghe đờn ca tài tử đặc trưng Nam Bộ...', '02 Th01'),
(24, 'Trekking vườn quốc gia Phong Nha Kẻ Bàng Quảng Bình', 'uploads/news24.png', 'Hành trình thám hiểm hang động kỳ vĩ, khám phá hệ sinh thái rừng nguyên sinh hoang dã độc đáo của di sản thiên nhiên thế giới...', '05 Th01'),
(25, 'Du lịch Hàn Quốc mùa hoa anh đào nở rộ cực kỳ lãng mạn', 'uploads/news25.png', 'Chiêm ngưỡng sắc hồng phấn rực rỡ của hoa anh đào khắp đường phố Seoul, công viên Yeouido và đảo Nami thanh bình thơ mộng...', '08 Th01'),
(26, 'Kinh nghiệm đi tour du lịch Dubai chi tiết cho người đi lần đầu', 'uploads/news26.png', 'Trải nghiệm cuộc sống thượng lưu, check-in khách sạn 7 sao Burj Al Arab, tham quan sa mạc Safari và thử thách cưỡi lạc đà đầy thú vị...', '10 Th01'),
(27, 'Khám phá tháp Eiffel và những điểm check-in hot nhất tại Paris', 'uploads/news27.png', 'Kinh nghiệm tham quan thủ đô Paris tráng lệ nước Pháp, đi du thuyền sông Seine thơ mộng và chụp ảnh cực nghệ tại quảng trường Trocadero...', '12 Th01'),
(28, 'Hành trình ngắm nhà hát con sò và cầu cảng Sydney nước Úc', 'uploads/news28.png', 'Khám phá thành phố cảng Sydney năng động, dạo chơi trên bãi biển Bondi cát trắng, ngắm hoàng hôn buông xuống cầu cảng Sydney nguy nga...', '15 Th01'),
(29, 'Kinh nghiệm săn tuyết mùa đông trên đỉnh Fansipan Sapa', 'uploads/news29.png', 'Chia sẻ những khoảnh khắc tuyệt vời khi chinh phục nóc nhà Đông Dương Fansipan ngập tràn tuyết trắng và băng giá kỳ ảo vào mùa đông...', '18 Th01'),
(30, 'Ăn hải sản tôm cua ngập tràn tại đảo Bình Ba Nha Trang', 'uploads/news30.png', 'Trải nghiệm đảo tôm hùm Bình Ba hoang sơ yên bình, thưởng thức hải sản tươi ngon đầm ấm ngay tại các nhà bè lộng gió đại dương...', '20 Th01'),
(31, 'Du lịch Thổ Nhĩ Kỳ bay khinh khí cầu ngắm thung lũng đá kỳ vĩ', 'uploads/news31.png', 'Hành trình bay khinh khí cầu ngắm bình minh trên thung lũng đá Cappadocia kỳ vĩ, tham quan thánh đường xanh Blue Mosque lộng lẫy...', '22 Th01'),
(32, 'Khám phá phố cổ Thượng Hải hiện đại pha lẫn cổ kính', 'uploads/news32.png', 'Check-in bến Thượng Hải sầm uất, dạo bước qua dự viên cổ kính hơn 400 năm tuổi và thưởng thức món bánh bao nước độc đáo...', '25 Th01'),
(33, 'Trải nghiệm leo đèo Mã Pí Lèng ngắm dòng sông Nho Quế xanh biếc', 'uploads/news33.png', 'Hành trình trekking leo núi hiểm trở ngắm trọn vẹn sự hùng vĩ của hẻm vực Tu Sản sâu nhất Đông Nam Á bên sông Nho Quế xanh lục...', '28 Th01'),
(34, 'Du lịch tự túc Bangkok Thái Lan: Đi đâu, chơi gì, ăn gì?', 'uploads/news34.png', 'Hướng dẫn chi tiết mua sắm tại chợ chatuchak, viếng đền bốn mặt linh thiêng và thưởng thức ẩm thực đường phố pad thai cay nồng...', '01 Th02'),
(35, 'Kinh nghiệm ngắm lá đỏ mùa thu tuyệt đẹp tại Kyoto Nhật Bản', 'uploads/news35.png', 'Hành trình chiêm ngưỡng cố đô Kyoto chìm đắm trong sắc phong đỏ rực rỡ, viếng chùa vàng Kinkakuji thanh bình lấp lánh ánh kim...', '03 Th02'),
(36, 'Khám phá đấu trường La Mã cổ kính Colosseum tại Rome nước Ý', 'uploads/news36.png', 'Tham quan công trình kiến trúc biểu tượng vĩ đại của đế chế La Mã cổ đại, tìm hiểu lịch sử đấu sĩ hào hùng đầy bí ẩn...', '05 Th02'),
(37, 'Trải nghiệm kỳ nghỉ dưỡng thượng lưu trên du thuyền Hạ Long 5 sao', 'uploads/news37.png', 'Thư giãn tuyệt đối trên du thuyền sang trọng, thưởng thức ẩm thực buffet hải sản biển và ngắm bình minh tuyệt đẹp trên vịnh Hạ Long...', '08 Th02'),
(38, 'Kinh nghiệm tham quan cung điện Versailles tráng lệ tại Pháp', 'uploads/news38.png', 'Khám phá cung điện hoàng gia xa hoa bậc nhất thế giới với sảnh gương lấp lánh và khu vườn ngự uyển rộng lớn tuyệt đẹp...', '10 Th02'),
(39, 'Top 5 bãi tắm cát trắng mịn hoang sơ nhất tại đảo ngọc Phú Quốc', 'uploads/news39.png', 'Cẩm nang khám phá các bãi tắm thiên đường hoang sơ ít người biết tại Phú Quốc như Bãi Sao, Bãi Khem, bãi tắm hòn Móng Tay...', '12 Th02'),
(40, 'Du lịch tự túc Seoul: Hướng dẫn chi tiết cách đi tàu điện ngầm', 'uploads/news40.png', 'Tự tin vi vu khám phá thủ đô Seoul Hàn Quốc với cẩm nang đi lại bằng tàu điện ngầm siêu rẻ, tiện lợi và an toàn nhất...', '15 Th02');
INSERT INTO `banner` (`id`, `name`, `image`, `url`, `position`, `tag`, `title`, `subtitle`, `description`, `btn_text`) VALUES
(1, 'Slide Hạ Long', 'uploads/slide1.jpg', 'index.php?act=sanphamct&id=1', 'slider', 'Tour Bán Chạy Nhất Hè 2026', 'TOUR HẠ LONG', 'chỉ từ <span>1.200.000đ</span>', 'Khám phá vẻ đẹp kỳ vĩ của Vịnh Hạ Long trên du thuyền sang trọng 5 sao, tham quan đảo Ti Tốp, Hang Sửng Sốt với mức giá cực kỳ ưu đãi.', 'Xem Chi Tiết Ngay'),
(2, 'Slide Phú Quốc', 'uploads/slide2.jpg', 'index.php?act=sanphamct&id=6', 'slider', 'Du lịch 4 ngày 3 đêm', 'PHÚ QUỐC', 'Vinpearl &amp; Safari chỉ từ <span>5.990.000đ</span>', 'Hành trình khám phá Đảo Ngọc xuất phát từ Hà Nội. Trọn gói vé máy bay khứ hồi, vui chơi không giới hạn tại VinWonders, Safari.', 'Hotline: 1900 0059'),
(3, 'Slide Sapa', 'uploads/slide3.jpg', 'index.php?act=sanphamct&id=2', 'slider', 'Nóc nhà Đông Dương', 'TOUR SAPA', 'Fansipan hùng vĩ chỉ từ <span>2.790.000đ</span>', 'Trải nghiệm cáp treo 3 dây hiện đại, ngắm toàn cảnh thung lũng Mường Hoa thơ mộng trong làn sương mù mờ ảo của thị trấn Sapa.', 'Đặt Tour Sapa'),
(4, 'Slide Đà Nẵng', 'uploads/slide4.jpg', 'index.php?act=sanphamct&id=3', 'slider', 'Thành Phố Đáng Sống', 'TOUR ĐÀ NẴNG', 'Bà Nà Hills chỉ từ <span>3.990.000đ</span>', 'Khám phá con đường di sản Miền Trung. Chiêm ngưỡng Cầu Vàng nổi tiếng thế giới tại Bà Nà Hills, dạo phố cổ Hội An rực rỡ.', 'Xem Chi Tiết'),
(5, 'Promo Banner 1', 'uploads/promo_banner1.png', 'index.php?act=sanpham', 'promo', NULL, 'Tết thật gần - Du lịch thật đã', NULL, NULL, NULL),
(6, 'Promo Banner 2', 'uploads/promo_banner2.png', 'index.php?act=sanpham', 'promo', NULL, 'Combo Hè cực hot - Giảm 40%', NULL, NULL, NULL),
(7, 'Sidebar Ad Banner', 'uploads/ninhchu_ad.jpg', 'index.php?act=sanpham&keyword=Ninh+Ch%E1%BB%AF', 'sidebar', NULL, 'Tour du lịch Ninh Chữ', NULL, NULL, NULL);
