(18, 'Tour Châu Âu đi qua nhiều nước rất đẹp, lịch trình khoa học không bị mệt.', 1, 92, '09:50 15/06/2026'),
(19, 'Check-in tháp Eiffel Pháp cực kỳ sang chảnh, hướng dẫn viên chụp ảnh rất có tâm.', 2, 93, '10:15 15/06/2026'),
