(40, 'Khách sạn trung tâm Sapa thuận tiện đi lại, nhân viên thân thiện.', 1, 2, '17:05 16/06/2026');
INSERT INTO `dichvu` (`id`, `name`, `icon`, `description`, `price`) VALUES
(1, 'Làm Visa Nhanh', '🎫', 'Hỗ trợ tư vấn hồ sơ, làm thủ tục xin visa nhanh chóng cho các tour quốc tế (Châu Á, Châu Âu, Mỹ, Úc).', 1500000),
(2, 'Thuê Xe Du Lịch', '🚗', 'Dịch vụ cho thuê xe du lịch đời mới từ 4 đến 45 chỗ tự lái hoặc có tài xế phục vụ chuyên nghiệp suốt hành trình.', 1200000),
(3, 'Vé Máy Bay Giá Rẻ', '✈️', 'Đặt vé máy bay khứ hồi nội địa và quốc tế từ các hãng hàng không uy tín với mức chiết khấu cực tốt cho đoàn du lịch.', 3500000),
(4, 'Hướng Dẫn Viên Bản Địa', '🗣️', 'Cung cấp hướng dẫn viên năng động, nhiệt tình, am hiểu văn hóa và thông thạo ngoại ngữ dẫn đoàn trọn gói.', 800000),
(5, 'Bảo Hiểm Du Lịch', '🛡️', 'Gói bảo hiểm du lịch quốc tế và nội địa cao cấp của PVI/Bảo Việt bảo vệ tối đa quyền lợi khách hàng lên tới 100 triệu đồng.', 200000),
(6, 'Đặt Phòng Khách Sạn', '🏨', 'Liên kết hệ thống resort/khách sạn cao cấp từ 3 đến 5 sao toàn quốc với mức giá ưu đãi đặc quyền.', 1800000);
