INSERT INTO `nhahang` (`id`, `name`, `image`, `description`, `price`, `address`, `rating`, `views`) VALUES
(1, 'Gỏi Cá Trích - Nhà Hàng Hòn Thơm Phú Quốc', 'uploads/seafood1.png', 'Món ăn đặc sản mang đậm hương vị biển khơi Phú Quốc. Cá trích tươi sống được phi lê mỏng, trộn cùng hành tây, dừa nạo và nước sốt chua ngọt thanh mát.', 150000, 'Khu đô thị An Thới, Phú Quốc', 4.8, 850),
(2, 'Tôm Hùm Nướng Bơ Tỏi - Nhà Hàng Cánh Buồm Nha Trang', 'uploads/seafood2.png', 'Tôm hùm bông Nha Trang tươi sống được nướng thơm lừng với sốt bơ tỏi béo ngậy. Thịt tôm dai ngọt hòa quyện cùng vị thơm nồng của tỏi phi.', 650000, 'Đường Trần Phú, Lộc Thọ, Nha Trang', 4.9, 1240),
(3, 'Cua Huỳnh Đế Hấp Sả - Nhà Hàng Bé Mặn Đà Nẵng', 'uploads/seafood3.png', 'Loại cua quý hiếm có thịt chắc ngọt bậc nhất. Hấp chín cùng sả tươi giữ trọn vị ngọt tự nhiên tinh khiết của cua biển Đà Nẵng.', 890000, 'Đường Võ Nguyên Giáp, Mân Thái, Sơn Trà, Đà Nẵng', 5.0, 1100),
(4, 'Chả Mực Giã Tay - Nhà Hàng Sen Cổ Kính Hạ Long', 'uploads/seafood4.png', 'Đặc sản nổi tiếng đất mỏ Quảng Ninh. Mực tươi ngon được giã tay thủ công, chiên vàng ruộm, dai giòn sần sật và thơm mùi gia vị hạt tiêu.', 220000, 'Khu du lịch Bãi Cháy, Hạ Long, Quảng Ninh', 4.7, 980),
(5, 'Lẩu Cá Đuối - Nhà Hàng Biển Đông Vũng Tàu', 'uploads/seafood5.png', 'Món lẩu trứ danh của phố biển Vũng Tàu. Cá đuối tươi thái mỏng nấu cùng măng chua, dọc mùng thơm lừng ăn kèm bún và nước mắm ớt cay.', 280000, 'Đường Nguyễn Trường Tộ, Phường 3, Vũng Tàu', 4.6, 740),
(6, 'Ghẹ Hấp Bia - Nhà Hàng Đại Dương Sầm Sơn', 'uploads/seafood6.png', 'Ghẹ xanh Sầm Sơn tươi sống được hấp cùng sả và bia hơi tạo mùi thơm đặc biệt. Ghẹ nhiều gạch, thịt ngọt lịm chấm cùng muối ớt chanh.', 450000, 'Đường Hồ Xuân Hương, Sầm Sơn, Thanh Hóa', 4.5, 620),
(7, 'Dông Cát Nướng Muối Ớt - Nhà Hàng Ngon Mũi Né', 'uploads/seafood7.png', 'Món ăn đặc sản độc lạ vùng cát nắng gió Bình Thuận. Thịt dông chắc ngọt tự nhiên được tẩm ướp muối ớt cay nồng rồi nướng vàng giòn trên than hồng.', 350000, 'Đường Nguyễn Đình Chiểu, Hàm Tiến, Phan Thiết', 4.7, 580),
(8, 'Còi Biên Mai Nướng Muối Ớt - Nhà Hàng Trùng Dương Phú Quốc', 'uploads/seafood8.png', 'Sự kết hợp giữa còi sò biên mai giòn dai ngọt tự nhiên cùng muối hạt và ớt chỉ thiên cay nồng, nướng chín tới giữ nguyên vị ngọt đậm đà.', 190000, 'Đường 30/4, Dương Đông, Phú Quốc', 4.8, 710),
(9, 'Bún Sứa Nha Trang - Quán Bà Thừa Nha Trang', 'uploads/seafood9.png', 'Tô bún nóng hổi với sứa biển giòn sần sật, chả cá chiên dai ngọt nước dùng ninh từ cá cờ thanh mát, mang hương vị đặc sản biển Nha Trang.', 45000, 'Đường Yersin, Vạn Thạnh, Nha Trang', 4.6, 690),
(10, 'Bánh Xèo Tôm Nhảy - Quán Gia Vỹ Quy Nhơn', 'uploads/seafood10.png', 'Vỏ bánh xèo giòn rụm bọc những chú tôm đất đỏ au tươi rói nhảy tanh tách. Ăn kèm rau sống bánh tráng và nước mắm đậu phộng chua ngọt ngon đúng điệu.', 50000, 'Đường Diên Hồng, Ngô Mây, Quy Nhơn', 4.9, 1300),
(11, 'Bún Chả Cá Quy Nhơn - Nhà Hàng Ngọc Liên', 'uploads/seafood11.png', 'Món ăn sáng quốc dân Quy Nhơn với chả cá thu chiên vàng, sợi bún nhỏ dai mềm và nước dùng ngọt đậm đà nấu từ đầu cá và xương cá biển.', 45005, 'Đường Nguyễn Huệ, Quy Nhơn, Bình Định', 4.8, 890),
(12, 'Ốc Hương Rang Muối Ớt - Quán Ốc Tự Nhiên Vũng Tàu', 'uploads/seafood12.png', 'Ốc hương size lớn tươi sống rang muối ớt khô giòn. Vị ốc giòn ngọt quyện muối cay mặn bám đều quanh vỏ ốc thơm lừng kích thích vị giác.', 120000, 'Đường Trần Phú, Phường 5, Vũng Tàu', 4.7, 1050),
(13, 'Sò Điệp Nướng Mỡ Hành - Nhà Hàng Gió Biển Phan Thiết', 'uploads/seafood13.png', 'Sò điệp tươi nướng mỡ hành thơm ngậy, rắc thêm đậu phộng rang giòn rụm. Vị sò ngọt thơm hòa quyện mỡ hành béo ngậy.', 90000, 'Đường Huỳnh Thúc Kháng, Mũi Né, Phan Thiết', 4.6, 530),
(14, 'Mực Một Nắng Nướng - Quán Biển Xanh Côn Đảo', 'uploads/seafood14.png', 'Mực ống câu đêm Côn Đảo phơi qua một nắng giòn ngọt, nướng mọi trên than hoa rách mép thơm phức chấm kèm tương ớt.', 250000, 'Đường Nguyễn Huệ, Côn Đảo, Bà Rịa - Vũng Tàu', 4.8, 670),
(15, 'Hải Sâm Hầm Nấm - Nhà Hàng Hải Cảng Phú Quốc', 'uploads/seafood15.png', 'Món ăn đại bổ thượng hạng chế biến từ hải sâm đen Phú Quốc hầm cùng nấm đông cô, hạt sen thơm bùi, bổ dưỡng cho sức khỏe.', 800000, 'Bãi Trường, Dương Tơ, Phú Quốc', 4.9, 420),
(16, 'Cá Sông Son Nướng - Nhà Hàng Phong Nha Quảng Bình', 'uploads/seafood16.png', 'Loại cá mú nước ngọt đặc sản nuôi trong lòng sông Son Phong Nha. Cá nướng muối ớt da giòn thịt thơm ngọt dai chấm muối cheo.', 220000, 'Khu du lịch Phong Nha, Bố Trạch, Quảng Bình', 4.7, 490),
(17, 'Hàu Sữa Nướng Phô Mai - Quán Hải Sản Ngon Vân Đồn', 'uploads/seafood17.png', 'Hàu sữa Vân Đồn béo ngậy nướng phô mai đút lò vàng ươm kéo sợi. Vị sữa hàu ngọt đậm đà tan chảy cùng phô mai béo ngậy.', 150000, 'Cảng Cái Rồng, Vân Đồn, Quảng Ninh', 4.8, 780),
(18, 'Cá Mú Hấp Hồng Kông - Nhà Hàng Sunrise Nha Trang', 'uploads/seafood18.png', 'Cá mú đỏ tươi sống hấp cùng nước tương Hồng Kông đặc chế, gừng sợi và hành lá. Thịt cá trắng ngần, dai ngọt đậm đà chuẩn vị hoa.', 480000, 'Đường Trần Phú, Xương Huân, Nha Trang', 4.9, 910),
(19, 'Mực Lá Hấp Gừng - Nhà Hàng Hải Sản San Hô Đà Nẵng', 'uploads/seafood19.png', 'Mực lá dày mình giòn ngọt được hấp chín tới cùng gừng tươi và hành hoa thơm nồng, ăn kèm nước mắm gừng chua ngọt đậm vị.', 180000, 'Đường Võ Nguyên Giáp, Phước Mỹ, Sơn Trà, Đà Nẵng', 4.7, 820),
(20, 'Sam Biển 7 Món - Nhà Hàng Quảng Yên Quảng Ninh', 'uploads/seafood20.png', 'Đặc sản sam biển độc đáo vùng Quảng Yên chế biến thành 7 món ngon khác nhau: trứng sam nướng, sụn sam nướng, sam xào sả ớt...', 350000, 'Đường Lê Lợi, Quảng Yên, Quảng Ninh', 4.6, 390),
(21, 'Ghẹ Xanh Luộc Sả - Nhà Hàng Gành Dầu Phú Quốc', 'uploads/seafood21.png', 'Ghẹ xanh đánh bắt tự nhiên từ vùng biển Gành Dầu tươi ngon nhiều thịt, hấp cách thủy cùng sả đập dập thơm lừng chấm muối ớt.', 400000, 'Mũi Gành Dầu, Phú Quốc, Kiên Giang', 4.8, 560),
(22, 'Bún Quậy Kiến Xây - Quán Kiến Xây Phú Quốc', 'uploads/seafood22.png', 'Món ăn độc lạ mang tính trải nghiệm cao ở Phú Quốc. Nước dùng nóng hổi chan vào tô chứa chả tôm, chả cá quết nhuyễn tươi rói.', 65000, 'Đường Bạch Đằng, Dương Đông, Phú Quốc', 4.9, 1580),
(23, 'Bánh Canh Chả Cá - Quán Cô Sáu Nha Trang', 'uploads/seafood23.png', 'Bánh canh bột lọc dai dai chan nước dùng ngọt thanh từ xương cá, chả cá chiên và chả cá hấp dẻo ngọt đậm đà hương vị biển.', 40000, 'Đường Vân Đồn, Phước Hòa, Nha Trang', 4.7, 740),
(24, 'Lẩu Cá Đuối Măng Chua - Quán Bảy Lượm Vũng Tàu', 'uploads/seafood24.png', 'Lẩu cá đuối nấu măng chua cay nồng ấm bụng đêm lạnh Vũng Tàu. Thịt cá đuối giòn sần sật chấm mắm ớt cực đã.', 260000, 'Đường Nguyễn Trường Tộ, Phường 3, Vũng Tàu', 4.8, 1120),
(25, 'Ốc Vú Nàng Nướng - Quán Hải Sản Côn Đảo', 'uploads/seafood25.png', 'Loại ốc đặc sản hình nón độc đáo ở Côn Đảo. Nướng chín trên than hồng chấm muối tiêu chanh, thịt ốc giòn ngọt dẻo bùi.', 180000, 'Đường Phạm Văn Đồng, Côn Đảo, Bà Rịa - Vũng Tàu', 4.8, 610),
(26, 'Cá Thu Một Nắng - Nhà Hàng Đồ Sơn Hải Phòng', 'uploads/seafood26.png', 'Cá thu tươi rói cắt lát dày phơi qua một nắng Đồ Sơn, rán vàng giòn hai mặt ăn kèm nước mắm tỏi ớt đưa cơm vô cùng.', 240000, 'Khu du lịch Vạn Hương, Đồ Sơn, Hải Phòng', 4.6, 480),
(27, 'Sò Huyết Lạc Lộc - Nhà Hàng Biển Cửa Lò', 'uploads/seafood27.png', 'Sò huyết Cửa Lò tươi ngon ngọt đậm, được nướng chín tái hoặc xào me chua ngọt hấp dẫn, giàu dinh dưỡng bổ máu.', 160000, 'Đường Bình Minh, Cửa Lò, Nghệ An', 4.5, 520),
(28, 'Tu Hài Nướng Mỡ Hành - Quán Cát Bà Hải Phòng', 'uploads/seafood28.png', 'Tu hài đảo Cát Bà nướng mỡ hành thơm phức dẻo ngọt giòn sần sật, món hải sản cao cấp không thể bỏ lỡ khi ghé thăm Hải Phòng.', 280000, 'Đường 1/4, Cát Bà, Hải Phòng', 4.7, 690),
(29, 'Sá Sùng Xào Tỏi - Nhà Hàng Minh Châu Quan Lạn', 'uploads/seafood29.png', 'Sá sùng tươi Minh Châu là đặc sản "vàng ròng" của biển khơi. Xào cùng tỏi tươi thơm nức, ngọt giòn ngọt lịm khó quên.', 950000, 'Bãi biển Minh Châu, Vân Đồn, Quảng Ninh', 4.9, 830),
(30, 'Cá Kèo Nướng Muối Ớt - Nhà Hàng Sông Nước Cà Mau', 'uploads/seafood30.png', 'Cá kèo tươi sống được xiên que tre nướng muối ớt vàng giòn. Ăn kèm rau răm và chấm mắm me chua ngọt cay nồng.', 110000, 'Đường Phan Ngọc Hiển, Phường 5, Cà Mau', 4.7, 410),
(31, 'Canh Chua Cá Bớp - Quán Duyên Biển Rạch Giá', 'uploads/seafood31.png', 'Canh chua cá bớp nấu ngổ, cà chua, thơm ngọt chua dịu mát lành. Thịt cá bớp béo ngậy dai ngon chuẩn vị miền Tây Nam Bộ.', 180000, 'Đường Tôn Đức Thắng, Rạch Giá, Kiên Giang', 4.6, 350),
(32, 'Mực Sim Trứng Hấp - Quán Ngon Sầm Sơn', 'uploads/seafood32.png', 'Những chú mực sim nhỏ nhắn ôm đầy trứng sữa căng tròn, hấp gừng chín tới giòn lịm bùi béo ngọt đậm đà vô cùng.', 200000, 'Đường Nguyễn Du, Sầm Sơn, Thanh Hóa', 4.7, 620),
(33, 'Bạch Tuộc Nướng Sa Tế - Quán Biển Chiều Đà Nẵng', 'uploads/seafood33.png', 'Bạch tuộc tươi sống ướp sốt sa tế cay nồng nướng than hoa vàng giòn. Thịt bạch tuộc dai ngọt sần sật hấp dẫn.', 140000, 'Đường Hoàng Sa, Thọ Quang, Sơn Trà, Đà Nẵng', 4.8, 890),
(34, 'Cá Bớp Nướng Muối Ớt - Quán Gió Biển Nha Trang', 'uploads/seafood34.png', 'Cá bớp biển cắt khoanh dày tẩm ướp muối ớt cay xè nướng chín vàng ươm, thịt cá ngọt béo quyện vị muối ớt cay đậm vị.', 250000, 'Đường Phạm Văn Đồng, Vĩnh Hòa, Nha Trang', 4.7, 730),
(35, 'Lẩu Ghẹ Chua Cay - Nhà Hàng Hương Biển Mũi Né', 'uploads/seafood35.png', 'Lẩu ghẹ chua cay nấu lẩu Thái chua ngọt đậm đà, ghẹ xanh Mũi Né ngọt thịt, ăn kèm rau muống rau nhút bún tươi.', 380000, 'Đường Huỳnh Tấn Phát, Mũi Né, Phan Thiết', 4.8, 660),
(36, 'Ốc Móng Tay Xào Bơ Tỏi - Quán Hải Sản Vũng Tàu', 'uploads/seafood36.png', 'Ốc móng tay xào sốt bơ tỏi thơm ngậy béo bùi, vị ốc giòn ngọt chấm bánh mì ăn kèm rau răm thơm mát tuyệt vời.', 90000, 'Đường Lê Hồng Phong, Thắng Tam, Vũng Tàu', 4.6, 810),
(37, 'Cá Đuối Nướng Sả Nghệ - Nhà Hàng Biển Xanh Đà Nẵng', 'uploads/seafood37.png', 'Cá đuối ướp nghệ tươi và sả băm nướng lá chuối thơm lừng. Thịt cá dai ngọt thơm nghệ vàng bắt mắt chấm mắm nêm.', 240000, 'Đường Nguyễn Tất Thành, Thanh Khê, Đà Nẵng', 4.7, 590),
(38, 'Tôm Tít Cháy Tỏi - Nhà Hàng Biển Ngọc Hạ Long', 'uploads/seafood38.png', 'Tôm tít (bề bề) Hạ Long tươi sống hấp chín sơ rồi cháy tỏi giòn rụm thơm nức, thịt tôm dai ngọt béo đậm vị tỏi phi.', 320000, 'Đường Hạ Long, Bãi Cháy, Quảng Ninh', 4.8, 940),
(39, 'Sò Mai Nướng Mỡ Hành - Quán Ăn Hàm Ninh Phú Quốc', 'uploads/seafood39.png', 'Sò mai khổng lồ nướng mỡ hành đậu phộng thơm ngậy trên than củi, thịt còi sò mai giòn dai ngọt lịm chấm muối ớt.', 130000, 'Cảng Hàm Ninh, Phú Quốc, Kiên Giang', 4.7, 470),
(40, 'Lẩu Cua Đồng Hải Sản - Nhà Hàng Đất Cảng Hải Phòng', 'uploads/seafood40.png', 'Nước lẩu cua đồng sánh riêu béo ngậy nhúng kèm mực tươi, tôm sú, chả cá Hải Phòng ăn cùng bánh đa đỏ đặc trưng.', 350000, 'Đường Lạch Tray, Ngô Quyền, Hải Phòng', 4.9, 1050),
(41, 'Lẩu Cá Đuối Lá Giang - Quán Gió Biển Vũng Tàu', 'uploads/seafood41.png', 'Thịt cá đuối tươi săn nấu cùng lá giang chua nhẹ, măng chua giòn, nước lẩu ngọt thơm ăn cùng bún tươi bốc khói nghi ngút.', 290000, 'Bãi Sau, Phường 2, Vũng Tàu', 4.8, 590),
(42, 'Ếch Xào Lăn Cát Bà - Quán Ăn Hương Biển Hải Phòng', 'uploads/seafood42.png', 'Đặc sản ếch núi Cát Bà thịt chắc, xào lăn cùng nước cốt dừa béo ngậy, nấm mèo giòn sần sật và sả ớt cay thơm nồng nàn.', 150000, 'Thị trấn Cát Bà, Hải Phòng', 4.7, 670),
(43, 'Tôm Hùm Tre Hấp Nước Dừa - Nhà Hàng Hải Sản Mũi Né', 'uploads/seafood43.png', 'Tôm hùm tre tươi xanh hấp cách thủy cùng nước dừa xiêm ngọt lịm. Thịt tôm trắng ngần chắc ngọt chấm muối ớt chanh.', 580000, 'Đường Nguyễn Đình Chiểu, Mũi Né, Phan Thiết', 4.9, 810),
(44, 'Cá Bớp Kho Tộ miền Tây - Quán Dân Dã Rạch Giá', 'uploads/seafood44.png', 'Kho tộ niêu đất chuẩn vị miền Tây. Cá bớp biển béo ngậy rim nước mắm tỏi ớt kẹo đặc, thêm vài cọng tiêu xanh thơm cay.', 130000, 'Khu lấn biển, Rạch Giá, Kiên Giang', 4.7, 430),
(45, 'Sò Lông Nướng Mỡ Hành - Quán Gió Biển Đà Nẵng', 'uploads/seafood45.png', 'Sò lông biển tươi nướng thơm lừng cùng mỡ hành, đậu phộng rang giòn thơm béo chấm kèm mắm chua ngọt hoặc muối tiêu.', 80000, 'Đường Võ Nguyên Giáp, Sơn Trà, Đà Nẵng', 4.6, 550),
(46, 'Bạch Tuộc Nhúng Giấm - Nhà Hàng Biển Động Nha Trang', 'uploads/seafood46.png', 'Bạch tuộc tươi giòn nhúng nước giấm sả chua ngọt nóng hổi cuốn bánh tráng rau sống, ngon ngất ngây chuẩn vị biển Nha Trang.', 220000, 'Đường Trần Phú, Nha Trang, Khánh Hòa', 4.8, 940),
(47, 'Cua Đá Đảo Chàm Hấp Sả - Quán Ăn Cù Lao Chàm', 'uploads/seafood47.png', 'Loại cua đặc sản sống trên vách đá Cù Lao Chàm ăn cây rừng nên thịt cực thơm chắc và bổ dưỡng, hấp sả ớt chấm muối tiêu.', 450000, 'Đảo Cù Lao Chàm, Hội An, Quảng Nam', 4.9, 600),
(48, 'Ếch Núi Chiên Bơ Tỏi - Nhà Hàng Đồ Sơn Hải Phòng', 'uploads/seafood48.png', 'Ếch núi Đồ Sơn tẩm bột chiên vàng giòn rụm bên ngoài, mềm ngọt bên trong, thơm nức mũi vị bơ tỏi phi thơm lừng.', 160000, 'Khu 2 Đồ Sơn, Hải Phòng', 4.6, 390),
(49, 'Cháo Hàu Sữa Cồn Hến - Quán Lăng Cô Huế', 'uploads/seafood49.png', 'Tô cháo hào sữa nóng hổi béo bùi nấu từ gạo tám thơm nức, hào sữa nhỏ béo ngậy xào gia vị tiêu hành lá cay nồng nàn.', 50000, 'Thị trấn Lăng Cô, Phú Lộc, Thừa Thiên Huế', 4.8, 720),
(50, 'Lẩu Cua Năm Căn Cà Mau - Quán Ngon Đất Mũi', 'uploads/seafood50.png', 'Đặc sản cua gạch Năm Căn nổi tiếng chắc thịt nhiều gạch, nấu lẩu chua cay đậm đà ngọt nước ngon trứ danh đất Mũi.', 390000, 'Khóm 1, Thị trấn Năm Căn, Cà Mau', 5.0, 1210),
(51, 'Tôm Mũ Ni Nướng Mỡ Hành - Nhà Hàng Hàm Ninh Phú Quốc', 'uploads/seafood51.png', 'Tôm mũ ni quý hiếm cắt đôi nướng lò cùng mỡ hành thơm lừng. Thịt tôm dai ngọt thơm như thịt tôm hùm.', 480000, 'Làng chài Hàm Ninh, Phú Quốc, Kiên Giang', 4.9, 880),
(52, 'Ghẹ Xanh Ram Me chua ngọt - Nhà Hàng Sông Lô Nha Trang', 'uploads/seafood52.png', 'Ghẹ xanh tươi nướng sơ rồi ram nước sốt me chua ngọt đậm đà, thịt ghẹ ngấm vị chua chua ngọt cay kích thích vô cùng.', 350000, 'Cầu Đá, Trần Phú, Nha Trang', 4.8, 740),
(53, 'Cá Mú Đỏ Hấp Gừng Hành - Nhà Hàng Hải Sản Côn Đảo', 'uploads/seafood53.png', 'Cá mú đỏ quý hiếm đánh bắt khơi xa Côn Đảo, hấp gừng hành hoa và nước tương nhạt giữ trọn vẹn vị ngọt thanh quý giá.', 750000, 'Đường Nguyễn Huệ, Côn Đảo, Bà Rịa - Vũng Tàu', 4.9, 530),
(54, 'Mực Ống Nhồi Thịt Sốt Cà - Quán Hải Sản Phan Thiết', 'uploads/seafood54.png', 'Mực ống biển Phan Thiết nhồi thịt nạc vai băm mộc nhĩ nướng chín rồi sốt cà chua kẹo đặc, vị ngọt dai hài hòa.', 160000, 'Đường Huỳnh Thúc Kháng, Phan Thiết, Bình Thuận', 4.7, 610),
(55, 'Ốc Nhảy Hấp Sả Lá Chanh - Nhà Hàng Biển Xanh Quy Nhơn', 'uploads/seafood55.png', 'Ốc nhảy đực Quy Nhơn hấp cách thủy sả lá chanh giòn ngọt. Thịt ốc dai sần sật chấm mắm gừng ớt cực ngon.', 120000, 'Đường Xuân Diệu, Quy Nhơn, Bình Định', 4.8, 670),
(56, 'Ếch Biển Trộn Gỏi chua cay - Nhà Hàng Vịnh Hạ Long', 'uploads/seafood56.png', 'Thịt ếch đồng/biển luộc xé phay trộn rau thơm, hành tây, cà rốt và nước mắm chua cay ngọt đậm vị giòn mát đưa bia.', 140000, 'Đường Hạ Long, Bãi Cháy, Hạ Long', 4.5, 410),
(57, 'Sò Huyết Cháy Tỏi Phô Mai - Quán Ốc Sài Gòn Vũng Tàu', 'uploads/seafood57.png', 'Sò huyết tươi cháy tỏi phi vàng giòn rụm và sốt bơ tỏi thơm lừng, món ốc khoái khẩu ăn kèm rau răm muối tiêu.', 150000, 'Phường Thắng Tam, Vũng Tàu', 4.7, 790),
(58, 'Tôm Sú Ủ Muối Hột nướng niêu - Nhà Hàng Biển Ngọc Đà Nẵng', 'uploads/seafood58.png', 'Tôm sú biển size lớn ủ trong niêu đất phủ muối hột nướng chín bằng nhiệt. Thịt tôm dai đậm đà ngọt tự nhiên.', 280000, 'Đường Võ Nguyên Giáp, Sơn Trà, Đà Nẵng', 4.8, 910),
(59, 'Hàu Sữa Ăn Sống Mù Tạt - Quán Hải Sản Lăng Cô', 'uploads/seafood59.png', 'Hàu sữa tươi khai thác trong ngày tách vỏ ăn sống vắt chanh kèm mù tạt cay nồng xộc lên mũi, ngọt lịm mát rượi.', 120000, 'Vịnh Lăng Cô, Phú Lộc, Thừa Thiên Huế', 4.9, 490),
(60, 'Lẩu Mực Đại Dương khổng lồ - Nhà Hàng Biển Đông Hạ Long', 'uploads/seafood60.png', 'Nồi lẩu chua cay nhúng mực ống khổng lồ tươi roi rói giòn sần sật, nước dùng ngọt lịm từ dứa cà chua sả ớt cực đã.', 450000, 'Đường Bãi Cháy, Hạ Long, Quảng Ninh', 4.9, 1120);
INSERT INTO `giaitri` (`id`, `name`, `image`, `description`, `price`, `address`, `rating`, `views`) VALUES
(1, 'VinWonders Phú Quốc - Thiên Đường Vui Chơi Giải Trí', 'uploads/entertainment1.png', 'Công viên chủ đề lớn nhất Việt Nam với quy mô hàng đầu châu Á. Trải nghiệm 6 phân khu độc đáo với hàng trăm trò chơi cảm giác mạnh, công viên nước khổng lồ và show diễn Once triệu đô.', 950000, 'Khu bãi Dài, Gành Dầu, Phú Quốc', 4.9, 850),
(2, 'Sun World Hòn Thơm Nature Park - Cáp Treo Vượt Biển', 'uploads/entertainment2.png', 'Hành trình vượt biển trên tuyến cáp treo 3 dây dài nhất thế giới. Khám phá công viên nước Aquatopia hiện đại và các hoạt động thể thao biển sôi động tại Bãi Trào.', 600000, 'Đảo Hòn Thơm, An Thới, Phú Quốc', 4.8, 790),
(3, 'Grand World Phú Quốc - Thành Phố Không Ngủ', 'uploads/entertainment3.png', 'Tổ hợp mua sắm, vui chơi giải trí và lễ hội đẳng cấp thế giới. Chiêm ngưỡng show diễn Sắc màu Venice lộng lẫy và trải nghiệm đi thuyền trên kênh đào đậm chất Ý.', 0, 'Khu Bãi Dài, Gành Dầu, Phú Quốc', 4.7, 980),
(4, 'Vinpearl Safari Phú Quốc - Vườn Thú Bán Hoang Dã', 'uploads/entertainment4.png', 'Công viên chăm sóc và bảo tồn động vật bán hoang dã đầu tiên tại Việt Nam. Trải nghiệm nhốt thú thả người độc đáo và gặp gỡ hàng ngàn cá thể động vật quý hiếm.', 650000, 'Khu Bãi Dài, Gành Dầu, Phú Quốc', 4.9, 1120),
(5, 'Sun World Ba Na Hills - Đường Lên Tiên Cảnh', 'uploads/entertainment5.png', 'Khu du lịch nổi tiếng với khí hậu mát mẻ quanh năm và công trình Cầu Vàng biểu tượng thế giới. Khám phá làng Pháp cổ kính và khu vui chơi Fantasy Park.', 900000, 'Tuyến cáp treo Bà Nà, Hòa Vang, Đà Nẵng', 5.0, 1540),
(6, 'Công Viên Châu Á Asia Park - Vòng Quay Mặt Trời', 'uploads/entertainment6.png', 'Công viên giải trí mang đậm phong cách văn hóa của nhiều quốc gia châu Á. Trải nghiệm vòng quay Sun Wheel khổng lồ ngắm nhìn toàn cảnh thành phố Đà Nẵng lung linh về đêm.', 200000, 'Đường 2/9, Hòa Cường Bắc, Hải Châu, Đà Nẵng', 4.6, 680),
(7, 'Công Viên Nước Núi Thần Tài - Suối Khoáng Nóng', 'uploads/entertainment7.png', 'Tổ hợp nghỉ dưỡng khoáng nóng thiên nhiên độc đáo giữa rừng núi mát mẻ. Tận hưởng các liệu pháp tắm bùn, tắm trà và công viên nước vui nhộn.', 400000, 'Khu bảo tồn thiên nhiên Bà Nà Núi Chúa, Hòa Vang, Đà Nẵng', 4.7, 560),
(8, 'VinWonders Nha Trang - Thiên Đường Biển Đảo', 'uploads/entertainment8.png', 'Công viên giải trí kỷ lục tọa lạc trên đảo Hòn Tre xinh đẹp. Khám phá đường trượt Zipline kỷ lục, bánh xe bầu trời khổng lồ và thế giới đại dương kỳ thú.', 800000, 'Đảo Hòn Tre, Vĩnh Nguyên, Nha Trang', 4.9, 1280),
(9, 'Tắm Bùn Khoáng Tháp Bà - Trị Liệu Thư Giãn', 'uploads/entertainment9.png', 'Địa điểm tắm bùn khoáng nóng lâu đời và nổi tiếng nhất Nha Trang. Giúp thư giãn cơ thể, phục hồi sức khỏe và làm đẹp da giữa không gian thiên nhiên yên tĩnh.', 250000, 'Đường Ngô Đến, Ngọc Hiệp, Nha Trang', 4.5, 430),
(10, 'Vịnh San Hô Nha Trang - Lặn Biển & Đi Bộ Dưới Đại Dương', 'uploads/entertainment10.png', 'Khám phá thế giới đại dương rực rỡ sắc màu của vịnh Nha Trang. Trải nghiệm đi bộ dưới biển ngắm rạn san hô tự nhiên và các loài cá biển độc đáo.', 450000, 'Vịnh Nha Trang, Khánh Hòa', 4.8, 910),
(11, 'Cáp Treo Fansipan Legend - Chinh Phục Nóc Nhà Đông Dương', 'uploads/entertainment11.png', 'Chinh phục đỉnh Fansipan huyền thoại ở độ cao 3.143m bằng hệ thống cáp treo ba dây hiện đại nhất thế giới, chiêm ngưỡng thung lũng Mường Hoa tuyệt đẹp.', 850000, 'Đường Nguyễn Chí Thanh, Sapa, Lào Cai', 4.9, 1420),
(12, 'Bản Cát Cát - Trải Nghiệm Văn Hóa Bản Địa Sapa', 'uploads/entertainment12.png', 'Ngôi làng cổ kính của đồng bào H\'Mông với những thửa ruộng bậc thang thơ mộng, cối xay nước khổng lồ và các điệu múa truyền thống đặc sắc.', 150000, 'San Sả Hồ, Sapa, Lào Cai', 4.6, 750),
(13, 'Cầu Kính Rồng Mây - Trải Nghiệm Cảm Giác Mạnh', 'uploads/entertainment13.png', 'Cầu kính cao nhất Việt Nam nằm tại đỉnh đèo Ô Quy Hồ. Trải nghiệm đi bộ trên kính trong suốt lơ lửng giữa mây trời và đồi núi hùng vĩ.', 400000, 'Đỉnh đèo Ô Quy Hồ, Tam Đường, Lai Châu', 4.7, 630),
(14, 'Khu Du Lịch Sun World Hạ Long Complex', 'uploads/entertainment14.png', 'Tổ hợp vui chơi giải trí đẳng cấp ven vịnh Hạ Long gồm cáp treo Nữ Hoàng vượt biển, vòng quay Mặt Trời và công viên nước lốc xoáy Typhoon Water Park.', 350000, 'Đường Bãi Cháy, Hạ Long, Quảng Ninh', 4.8, 1150),
(15, 'Yoko Onsen Quang Hanh - Tắm Khoáng Nóng Chuẩn Nhật', 'uploads/entertainment15.png', 'Khu nghỉ dưỡng tắm khoáng nóng mang đậm kiến trúc Nhật Bản giữa thung lũng đá Quang Hanh. Tận hưởng nguồn khoáng chất quý báu trị liệu cơ thể.', 1200000, 'Phường Quang Hanh, Cẩm Phả, Quảng Ninh', 4.9, 870),
(16, 'Khu Du Lịch Sinh Thái Tràng An - Danh Thắng Di Sản Kép', 'uploads/entertainment16.png', 'Trải nghiệm ngồi đò nan len lỏi qua các hang động xuyên thủy kỳ ảo, tham quan các đền thờ cổ kính giữa non nước hữu tình của danh thắng di sản thế giới.', 250000, 'Tràng An, Trường Yên, Hoa Lư, Ninh Bình', 5.0, 1890),
(17, 'Hang Múa - Check-in Vạn Lý Trường Thành Thu Nhỏ', 'uploads/entertainment17.png', 'Chinh phục gần 500 bậc đá lên đỉnh núi Múa để ngắm trọn vẹn toàn cảnh cánh đồng lúa chín vàng óng ả và dòng sông Ngô Đồng uốn lượn tại Tam Cốc.', 100000, 'Ninh Xuân, Hoa Lư, Ninh Bình', 4.7, 950),
(18, 'Đường Đèo Mã Pí Lèng - Chinh Phục Cung Đường Huyền Thoại', 'uploads/entertainment18.png', 'Một trong tứ đại đỉnh đèo của Việt Nam, cung đường hiểm trở hùng vĩ uốn lượn bên vách đá dựng đứng, mở ra tầm nhìn tuyệt đỉnh xuống hẻm vực Tu Sản.', 0, 'Đường Hạnh Phúc, Mèo Vạc, Hà Giang', 4.9, 1340),
(19, 'Dạo Thuyền Sông Nho Quế - Khám Phá Hẻm Vực Tu Sản', 'uploads/entertainment19.png', 'Trải nghiệm ngồi thuyền lướt nhẹ trên dòng sông Nho Quế xanh biếc như ngọc, đi qua hẻm vực Tu Sản sâu nhất Đông Nam Á đầy kỳ vĩ.', 100000, 'Sông Nho Quế, Pải Lủng, Mèo Vạc, Hà Giang', 4.8, 1220),
(20, 'Khu Du Lịch Thung Lũng Tình Yêu - Đà Lạt Thơ Mộng', 'uploads/entertainment20.png', 'Thắng cảnh lãng mạn bậc nhất Đà Lạt với hồ Đa Thiện trong vắt ẩn hiện giữa rừng thông xanh ngút ngàn, các vườn hoa rực rỡ và đồi Vọng Cảnh.', 250000, 'Đường Mai Anh Đào, Phường 8, Đà Lạt', 4.6, 820),
(21, 'Đu Dây Vượt Thác Datanla - Trải Nghiệm Mạo Hiểm', 'uploads/entertainment21.png', 'Hành trình vượt qua thử thách đu dây, leo vách đá dựng đứng và nhảy tự do xuống dòng thác nước Datanla xối xả giữa rừng nguyên sinh.', 800000, 'Đèo Prenn, Phường 3, Đà Lạt', 4.8, 590),
(22, 'Puppy Farm Đà Lạt - Nông Trại Cún Siêu Dễ Thương', 'uploads/entertainment22.png', 'Địa điểm check-in cực hot thu hút giới trẻ với hàng chục giống cún dễ thương, thân thiện, kết hợp vườn cà chua, dâu tây và hoa hướng dương rực rỡ.', 100000, 'Đường Cam Ly, Phường 7, Đà Lạt', 4.7, 710),
(23, 'Khu Du Lịch Văn Hóa Suối Tiên - Điểm Hẹn Lịch Sử', 'uploads/entertainment23.png', 'Công viên giải trí mang chủ đề lịch sử, truyền thuyết văn hóa Việt Nam với biển Tiên Đồng Ngọc Nữ và hàng trăm trò chơi vui nhộn cho gia đình.', 120000, 'Xa lộ Hà Nội, Tân Phú, Quận 9, TP. HCM', 4.5, 960),
(24, 'Thảo Cầm Viên Sài Gòn - Vườn Thú Lâu Đời Nhất', 'uploads/entertainment24.png', 'Lá phổi xanh giữa trung tâm thành phố sầm uất. Nơi nuôi dưỡng hàng ngàn cá thể động thực vật quý hiếm, điểm vui chơi dã ngoại lý tưởng cuối tuần.', 60000, 'Đường Nguyễn Bỉnh Khiêm, Bến Nghé, Quận 1, TP. HCM', 4.4, 880),
(25, 'Đài Quan Sát Landmark 81 Skyview - Ngắm Toàn Cảnh Sài Gòn', 'uploads/entertainment25.png', 'Trải nghiệm ngắm nhìn toàn cảnh thành phố rực rỡ từ tầng 79-81 của tòa nhà cao nhất Việt Nam, thử cảm giác đi trên cầu kính lơ lửng.', 400000, 'Đường Điện Biên Phủ, Phường 22, Bình Thạnh, TP. HCM', 4.7, 1050),
(26, 'Chợ Nổi Cái Răng - Trải Nghiệm Sông Nước Miền Tây', 'uploads/entertainment26.png', 'Khám phá nét văn hóa giao thương độc đáo trên sông nước Mekong từ sáng sớm, thưởng thức tô hủ tiếu nóng hổi ngay trên những chiếc ghe chao đảo.', 50000, 'Sông Cần Thơ, Cái Răng, Cần Thơ', 4.8, 1140),
(27, 'Khu Du Lịch Sinh Thái Mỹ Khánh - Trải Nghiệm Dân Dã', 'uploads/entertainment27.png', 'Hòa mình vào cuộc sống miệt vườn Nam Bộ, tham gia đua heo, đua chó, câu cá sấu, thưởng thức các món ăn dân dã và nghe đờn ca tài tử.', 100000, 'Đường Lộ Vòng Cung, Mỹ Khánh, Phong Điền, Cần Thơ', 4.5, 730),
(28, 'Universal Studios Singapore - Đảo Sentosa', 'uploads/entertainment28.png', 'Công viên giải trí chủ đề điện ảnh Hollywood đầu tiên tại Đông Nam Á. Trải nghiệm tàu lượn siêu tốc Transformers và lâu đài cổ tích Far Far Away.', 1350000, '8 Sentosa Gateway, Singapore', 4.9, 2100),
(29, 'Gardens by the Bay - Siêu Công Viên Nhân Tạo', 'uploads/entertainment29.png', 'Chiêm ngưỡng những siêu cây khổng lồ phát sáng rực rỡ ban đêm, khu nhà kính Cloud Forest với thác nước nhân tạo đổ từ trên cao kỳ ảo.', 800000, '18 Marina Gardens Dr, Singapore', 4.9, 1950),
(30, 'Sở Thú Đêm Night Safari - Khám Phá Thú Đêm Độc Đáo', 'uploads/entertainment30.png', 'Trải nghiệm sở thú đêm đầu tiên trên thế giới bằng xe điện chuyên dụng, quan sát tập tính săn mồi của các loài thú hoang dã khi màn đêm buông xuống.', 950000, '80 Mandai Lake Rd, Singapore', 4.7, 1430),
(31, 'Tokyo Disneyland - Thiên Đường Cổ Tích', 'uploads/entertainment31.png', 'Công viên giải trí mang thương hiệu Disney đầu tiên tại châu Á, tái hiện hoàn hảo thế giới thần thoại của các nhân vật hoạt hình huyền thoại.', 1600000, '1-1 Maihama, Urayasu, Chiba, Tokyo, Nhật Bản', 4.9, 2500),
(32, 'Tokyo DisneySea - Công Viên Nước Huyền Ảo', 'uploads/entertainment32.png', 'Công viên nước giải trí duy nhất mang chủ đề biển cả của Disney trên thế giới, bao gồm các phân khu cảng viễn tưởng kỳ thú.', 1600000, '1-13 Maihama, Urayasu, Chiba, Tokyo, Nhật Bản', 4.9, 2300),
(33, 'Đài Quan Sát Shibuya Sky - Ngắm Tokyo Từ Trên Cao', 'uploads/entertainment33.png', 'Tọa lạc tại đỉnh tòa tháp Shibuya Scramble Square sầm uất. Ngắm nhìn toàn cảnh ngã tư Shibuya huyền thoại và đỉnh núi Phú Sĩ từ xa.', 550000, '2 Chome-24-12 Shibuya, Tokyo, Nhật Bản', 4.8, 1780),
(34, 'Disneyland Paris - Phép Màu Cổ Tích Giữa Lòng Nước Pháp', 'uploads/entertainment34.png', 'Hòa mình vào thế giới cổ tích huyền ảo của Walt Disney tại Paris, tham gia các buổi diễu hành đầy màu sắc và bắn pháo hoa lộng lẫy đêm.', 1800000, 'Boulevard de Parc, Chessy, Pháp', 4.8, 1420),
(35, 'Dạo Thuyền Sông Seine - Chiêm Ngưỡng Paris Lãng Mạn', 'uploads/entertainment35.png', 'Hành trình lãng mạn dạo thuyền trên dòng sông Seine thơ mộng, ngắm nhìn tháp Eiffel, nhà thờ Đức Bà và các cây cầu cổ kính lung linh ánh đèn.', 350000, 'Port de la Bourdonnais, Paris, Pháp', 4.7, 1310),
(36, 'Bảo Tàng Louvre - Thiên Đường Nghệ Thuật Thế Giới', 'uploads/entertainment36.png', 'Bảo tàng nghệ thuật lớn nhất thế giới, nơi lưu giữ kiệt tác bức tranh Mona Lisa của Leonardo da Vinci và tượng nữ thần sắc đẹp Venus.', 450000, 'Rue de Rivoli, Paris, Pháp', 4.9, 2010),
(37, 'Vòng Quay Khổng Lồ London Eye - Ngắm Thủ Đô Nước Anh', 'uploads/entertainment37.png', 'Trải nghiệm ngắm nhìn toàn cảnh dòng sông Thames và tòa nhà Quốc hội Anh từ độ cao 135m trên vòng quay khổng lồ mang tính biểu tượng.', 950000, 'Riverside Building, Westminster Bridge Rd, London, Anh', 4.8, 1530),
(38, 'Warner Bros. Studio Tour - Khám Phá Thế Giới Harry Potter', 'uploads/entertainment38.png', 'Bước chân vào thế giới phép thuật huyền bí của Harry Potter, chiêm ngưỡng đại sảnh đường Hogwarts, hẻm Xéo và các đạo cụ làm phim chân thực.', 1500000, 'Studio Tour Dr, Leavesden, Watford, Anh', 4.9, 1890),
(39, 'Lotte World Seoul - Công Viên Giải Trí Trong Nhà Lớn Nhất', 'uploads/entertainment39.png', 'Công viên giải trí tích hợp khổng lồ gồm khu vui chơi phiêu lưu trong nhà lớn nhất thế giới và đảo ma thuật ngoài trời lãng mạn giữa hồ.', 1100000, '240 Olympic-ro, Songpa-gu, Seoul, Hàn Quốc', 4.8, 1650),
(40, 'Everland Resort - Công Viên Giải Trí Ngoài Trời Lớn Nhất', 'uploads/entertainment40.png', 'Khám phá 5 phân khu trò chơi độc đáo đầy phơi khởi, vườn thú Zootopia hoang dã và đường trượt tàu lượn bằng gỗ T-Express dốc nhất thế giới.', 1200000, '199 Everland-ro, Cheoin-gu, Yongin-si, Gyeonggi-do, Hàn Quốc', 4.9, 1820),
(41, 'Đài Quan Sát N Seoul Tower - Khóa Tình Yêu Lãng Mạn', 'uploads/entertainment41.png', 'Biểu tượng lãng mạn của thủ đô Seoul tọa lạc trên đỉnh núi Namsan, nơi lưu giữ hàng triệu chiếc khóa tình yêu rực rỡ sắc màu.', 300000, '105 Namsangongwon-gil, Yongsan-gu, Seoul, Hàn Quốc', 4.7, 1450),
(42, 'Chợ Nổi Damnoen Saduak - Trải Nghiệm Sông Nước Độc Đáo', 'uploads/entertainment42.png', 'Khám phá ngôi chợ nổi truyền thống sầm uất bậc nhất của Thái Lan, mua sắm hoa quả tươi ngon và đồ thủ công mỹ nghệ trực tiếp trên thuyền.', 250000, 'Damnoen Saduak, Ratchaburi, Thái Lan', 4.6, 910),
(43, 'Safari World Bangkok - Vườn Thú Bán Hoang Dã Lớn Nhất', 'uploads/entertainment43.png', 'Trải nghiệm ngồi xe bus chuyên dụng đi qua rừng thú hoang dã ngắm hổ sư tử, xem các show biểu diễn cá heo và khỉ đấm bốc vui nhộn.', 750000, '99 Panya Indra Rd, Sam Wa Tawan Tok, Khlong Sam Wa, Bangkok, Thái Lan', 4.8, 1280),
(44, 'Taronga Zoo Sydney - Vườn Thú Bên Vịnh Biển Đẹp Nhất', 'uploads/entertainment44.png', 'Vườn thú độc đáo tọa lạc bên bờ vịnh Sydney, nơi bạn có thể vừa ngắm nhìn các loài động vật bản địa Úc vừa chiêm ngưỡng nhà hát con sò.', 780000, 'Bradleys Head Rd, Mosman, Sydney, Úc', 4.8, 890),
(45, 'Dạo Thuyền Trên Vịnh Sydney - Ngắm Nhà Hát Con Sò', 'uploads/entertainment45.png', 'Chuyến dạo thuyền sang trọng quanh vịnh cảng Sydney, ngắm hoàng hôn buông xuống cầu cảng nguy nga và nhà hát Opera House nổi tiếng.', 650000, 'Circular Quay, Sydney, Úc', 4.7, 1020),
(46, 'Công Viên Nước Aquaventure Dubai - Khám Phá Đại Dương', 'uploads/entertainment46.png', 'Công viên nước khổng lồ tọa lạc trên đảo nhân tạo Palm Jumeirah với các đường trượt mạo hiểm xuyên qua hồ chứa đầy cá mập.', 2100000, 'Atlantis The Palm, Crescent Rd, Dubai, UAE', 4.9, 1540),
(47, 'Trải Nghiệm Trượt Tuyết Ski Dubai - Giữa Sa Mạc Nóng Bỏng', 'uploads/entertainment47.png', 'Công viên tuyết trong nhà khổng lồ đầu tiên tại Trung Đông, tận hưởng cảm giác trượt tuyết lạnh giá và ngắm những chú chim cánh cụt.', 1800000, 'Sheikh Zayed Rd, Al Barsha, Dubai, UAE', 4.8, 1100),
(48, 'Đài Quan Sát Burj Khalifa At The Top - Tòa Nhà Cao Nhất Thế Giới', 'uploads/entertainment48.png', 'Chiêm ngưỡng toàn cảnh sa mạc và vịnh biển Dubai rực rỡ từ đài quan sát ở tầng 124 và 125 của tòa tháp cao nhất hành tinh.', 1200000, '1 Sheikh Mohammed bin Rashid Blvd, Dubai, UAE', 4.9, 2800),
(49, 'Đấu Trường La Mã Colosseum - Khám Phá Lịch Sử Rome', 'uploads/entertainment49.png', 'Khám phá kỳ quan kiến trúc cổ đại vĩ đại nhất của đế chế La Mã, tìm hiểu lịch sử các cuộc giao đấu sinh tử của các đấu sĩ kiêu hùng.', 450000, 'Piazza del Colosseo, Rome, Ý', 4.9, 1980),
(50, 'Du Thuyền Khám Phá Kênh Đào Venice Lãng Mạn', 'uploads/entertainment50.png', 'Trải nghiệm ngồi thuyền Gondola truyền thống lướt nhẹ trên các dòng kênh đào Venice thơ mộng, ngắm nhìn những tòa nhà cổ kính.', 800000, 'Piazza San Marco, Venice, Ý', 4.9, 1430);
INSERT INTO `duthuyen` (`id`, `name`, `image`, `description`, `price`, `address`, `rating`, `views`) VALUES
(1, 'Du thuyền Emperor Cruises Nha Trang', 'uploads/cruise1.png', 'Trải nghiệm du thuyền hoàng gia lấy cảm hứng từ vua Bảo Đại. Hải trình ngắm hoàng hôn vịnh Nha Trang lung linh kèm tiệc tối sang trọng.', 1250000, 'Cảng Nha Trang, Vĩnh Nguyên, Nha Trang', 4.9, 1200),
(2, 'Du thuyền Ambassador Hạ Long Premium', 'uploads/cruise2.png', 'Siêu du thuyền 5 sao lớn nhất Vịnh Hạ Long với 46 cabin sang trọng, bể bơi kính ngoài trời và sàn tắm nắng rộng tới 870m2.', 3200000, 'Cảng tàu khách quốc tế Hạ Long, Bãi Cháy', 4.8, 1420),
(3, 'Du thuyền Stellar of the Seas Lan Hạ', 'uploads/cruise3.png', 'Du thuyền thiết kế đương đại sang trọng bậc nhất vịnh Lan Hạ, sở hữu bể bơi tam giác tràn bờ, sân golf mini và hầm rượu vang.', 4500000, 'Bến Gót, Cát Hải, Hải Phòng (Vịnh Lan Hạ)', 4.9, 1890),
(4, 'Du thuyền Heritage Bình Chuẩn Cát Bà', 'uploads/cruise4.png', 'Du thuyền nghệ thuật mang phong cách Đông Dương những năm 1930. Chiêm ngưỡng tranh vẽ của danh họa Phạm Lực và thư viện Bạch Thái Bưởi.', 3800000, 'Cảng tàu khách quốc tế Tuần Châu, Quảng Ninh', 4.8, 1560),
(5, 'Du thuyền Capella Lan Hạ đẳng cấp', 'uploads/cruise5.png', 'Nổi bật với cầu trượt nước từ tầng cao thẳng xuống biển độc đáo. Du thuyền sở hữu hồ bơi Oasis, bể sục Jacuzzi và rạp chiếu phim mini.', 4200000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.9, 2100),
(6, 'Du thuyền Paradise Elegance Hạ Long', 'uploads/cruise6.png', 'Kiệt tác du thuyền vỏ thép mang vẻ đẹp tân cổ điển Pháp, trải nghiệm lớp học nấu ăn trên sân thượng rộng lớn ngắm hoàng hôn.', 3500000, 'Đảo Tuần Châu, Hạ Long, Quảng Ninh', 4.7, 1150),
(7, 'Du thuyền Indochine Lan Hạ Premium', 'uploads/cruise7.png', 'Không gian mang đậm kiến trúc thuộc địa Đông Dương cổ kính, thưởng thức bữa tối gourmet 5 sao và dịch vụ mát-xa chuyên nghiệp.', 3700000, 'Bến phà Got, Cát Hải, Hải Phòng', 4.8, 980),
(8, 'Du thuyền Orchid Lan Hạ sang trọng', 'uploads/cruise8.png', 'Thiết kế thanh lịch với chỉ 14 cabin rộng rãi, toàn bộ phòng nghỉ đều có ban công riêng hướng vịnh ngắm cảnh tuyệt đẹp.', 3900000, 'Bến Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.8, 860),
(9, 'Du thuyền Mon Chéri Lan Hạ 5 sao', 'uploads/cruise9.png', 'Du thuyền sang trọng phục vụ thực đơn Halal đạt chứng nhận quốc tế và các món ăn đặc biệt phù hợp cho du khách ăn kiêng.', 3600000, 'Cảng tàu khách quốc tế Tuần Châu, Quảng Ninh', 4.6, 920),
(10, 'Du thuyền Elite of the Seas siêu sang', 'uploads/cruise10.png', 'Siêu du thuyền 6 sao đầu tiên tại Việt Nam có bể bơi dát vàng tràn bờ, dịch vụ quản gia 24/7 và bãi đáp trực thăng sang trọng.', 6500000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.9, 2450),
(11, 'Du thuyền Scarlet Pearl Lan Hạ', 'uploads/cruise11.png', 'Lấy cảm hứng từ ngọc trai biển khơi, trang bị thuyền buồm catamaran sang trọng đưa khách đi lặn ngắm san hô tại vịnh Lan Hạ.', 4100000, 'Cảng tàu khách quốc tế Hạ Long, Quảng Ninh', 4.8, 1310),
(12, 'Du thuyền Catherine Hạ Long đẳng cấp', 'uploads/cruise12.png', 'Siêu du thuyền 5 sao thiết kế tinh xảo dành riêng cho các cặp đôi du lịch lãng mạn, trang bị spa xông hơi hồng ngoại đẳng cấp.', 4400000, 'Cảng tàu khách quốc tế Tuần Châu, Hạ Long', 4.9, 1750),
(13, 'Du thuyền Essence Grand Hạ Long siêu du thuyền', 'uploads/cruise13.png', 'Du thuyền xanh thân thiện với môi trường sở hữu bãi đáp trực thăng, rạp chiếu phim 3D, phòng tập golf 3D hiện đại bậc nhất.', 4800000, 'Cảng tàu khách quốc tế Tuần Châu, Hạ Long', 4.9, 2200),
(14, 'Du thuyền Sea Octopus Hạ Long sang chảnh', 'uploads/cruise14.png', 'Thiên đường ẩm thực nổi trên biển vịnh Hạ Long, hải trình 4 tiếng ngắm hoàng hôn lung linh và tiệc buffet hải sản thượng hạng.', 1450000, 'Cảng tàu khách quốc tế Hạ Long, Bãi Cháy', 4.7, 1050),
(15, 'Du thuyền Rita Cruise Lan Hạ 5 sao', 'uploads/cruise15.png', 'Du thuyền có bể bơi ngoài trời hiện đại, phòng tập gym hướng vịnh và các hoạt động chèo thuyền kayak khám phá hang Sáng Tối.', 3450000, 'Cảng tàu khách quốc tế Tuần Châu, Quảng Ninh', 4.6, 880),
(16, 'Du thuyền Rosy Cruise Lan Hạ thanh lịch', 'uploads/cruise16.png', 'Hải trình độc đáo khám phá khu vực hoang sơ ít người biết tại vịnh Lan Hạ, phục vụ đồ uống chào mừng cao cấp khi lên tàu.', 3200000, 'Bến Tuần Châu, Hạ Long, Quảng Ninh', 4.5, 760),
(17, 'Du thuyền Le Theatre Lan Hạ (Du Thuyền Nhà Hát)', 'uploads/cruise17.png', 'Thiết kế lấy cảm hứng từ nhà hát tân cổ điển hoành tráng, sở hữu cabin siêu rộng và phòng ăn mang kiến trúc hoàng gia.', 4000000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.8, 1490),
(18, 'Du thuyền Hermes Hạ Long sang trọng', 'uploads/cruise18.png', 'Sở hữu hồ bơi bốn mùa ngoài trời, dịch vụ spa trị liệu đá nóng cao cấp và phòng suite có bồn tắm jacuzzi hướng vịnh.', 4300000, 'Cảng tàu khách quốc tế Tuần Châu, Hạ Long', 4.8, 1250),
(19, 'Du thuyền Doris Cruise Lan Hạ hiện đại', 'uploads/cruise19.png', 'Được đánh giá cao nhờ thái độ phục vụ tận tâm của thủy thủ đoàn, buffet hải sản phong phú và các lớp thái cực quyền buổi sáng.', 3150000, 'Bến Tuần Châu, Hạ Long, Quảng Ninh', 4.7, 950),
(20, 'Du thuyền Sena Cruise Lan Hạ ấm cúng', 'uploads/cruise20.png', 'Du thuyền mang phong cách boutique nhỏ xinh, ấm cúng bằng gỗ mun cổ truyền mang lại trải nghiệm hoài niệm yên tĩnh.', 2800000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.6, 680),
(21, 'Du thuyền Sealife Legend Lan Hạ', 'uploads/cruise21.png', 'Trang bị phòng nghỉ thượng lưu có ban công rộng, lớp học nấu các món ăn truyền thống Việt Nam và quầy bar rượu vang sang trọng.', 3950000, 'Cảng tàu khách quốc tế Tuần Châu, Quảng Ninh', 4.8, 1100),
(22, 'Du thuyền Peony Cruise Lan Hạ', 'uploads/cruise22.png', 'Đặt tên theo hoa mẫu đơn kiêu sa, du thuyền mang tông màu trắng hồng nhẹ nhàng lãng mạn vô cùng thích hợp cho trăng mật.', 3300000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.7, 850),
(23, 'Du thuyền Bhaya Classic Hạ Long', 'uploads/cruise23.png', 'Thương hiệu du thuyền gỗ truyền thống lâu đời và uy tín bậc nhất vịnh Hạ Long, đưa bạn tham quan làng chài nổi Vung Viêng.', 2900000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.6, 790),
(24, 'Du thuyền Âu Cơ Hạ Long đẳng cấp', 'uploads/cruise24.png', 'Du thuyền vỏ thép sang trọng chạy hải trình 3 ngày 2 đêm độc quyền khám phá vịnh Hạ Long, vịnh Lan Hạ và đảo Cát Bà xanh mát.', 5800000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.8, 1240),
(25, 'Du thuyền Signature Halong Cruise', 'uploads/cruise25.png', 'Nổi tiếng với thiết kế hoàng gia bằng gỗ quý sang trọng, phục vụ bữa tối nướng BBQ trực tiếp trên boong tàu lộng gió.', 3650000, 'Cảng tàu khách quốc tế Hạ Long, Bãi Cháy', 4.7, 1010),
(26, 'Du thuyền Pelican Halong Cruise', 'uploads/cruise26.png', 'Hải trình an toàn tuyệt đối với vỏ thép chắc chắn, cabin thiết kế hiện đại có cửa kính sát trần ngắm trọn vẹn vịnh đá vôi.', 3000000, 'Cảng tàu khách quốc tế Tuần Châu, Quảng Ninh', 4.5, 620),
(27, 'Du thuyền Glory Legend Hạ Long giá tốt', 'uploads/cruise27.png', 'Sự lựa chọn hoàn hảo cho gia đình nghỉ dưỡng cuối tuần với chi phí tiết kiệm, tham quan hang Sửng Sốt và đảo Ti Tốp.', 2600000, 'Cảng tàu khách quốc tế Tuần Châu, Hạ Long', 4.5, 840),
(28, 'Du thuyền Swan Cruise vịnh Bái Tử Long', 'uploads/cruise28.png', 'Đưa bạn lánh xa đám đông ồn ào để khám phá vẻ đẹp hoang sơ tĩnh lặng của vịnh Bái Tử Long kỳ bí và hoang dã.', 2750000, 'Cảng tàu khách quốc tế Hạ Long, Quảng Ninh', 4.7, 910),
(29, 'Du thuyền Dragon Legend Bái Tử Long', 'uploads/cruise29.png', 'Tác phẩm nghệ thuật chạm khắc gỗ tinh xảo mang đậm dấu ấn văn hóa trống đồng Đông Sơn cổ đại trong lòng du thuyền.', 4200000, 'Cảng quốc tế Hòn Gai, Hạ Long, Quảng Ninh', 4.9, 1370),
(30, 'Du thuyền Indochina Sails Hạ Long', 'uploads/cruise30.png', 'Trải nghiệm ngủ đêm trên vịnh bằng cánh buồm cam truyền thống lãng mạn, thưởng thức nhạc dân tộc trên boong tàu ban đêm.', 3400000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.6, 750),
(31, 'Du thuyền Emperor Cruises Phú Quốc Hoàng Gia', 'uploads/cruise31.png', 'Ngắm hoàng hôn nam đảo Phú Quốc trên chiếc du thuyền gỗ kiểu cổ sang trọng, phục vụ tôm hùm nướng và rượu vang cao cấp.', 1350000, 'Cảng An Thới, Phú Quốc, Kiên Giang', 4.9, 1100),
(32, 'Du thuyền Sarita Phú Quốc Catamaran', 'uploads/cruise32.png', 'Du thuyền buồm hai thân Catamaran đầu tiên tại Phú Quốc mang phong cách quý tộc Pháp, lặn ngắm san hô tại hòn Móng Tay.', 1500000, 'Bến cảng An Thới, Phú Quốc, Kiên Giang', 4.8, 1340),
(33, 'Du thuyền Nautilus Phú Quốc hiện đại', 'uploads/cruise33.png', 'Tổ hợp vui chơi giải trí trên biển Phú Quốc với các môn thể thao mạo hiểm: dù bay, mô tô nước, đi bộ dưới đáy đại dương.', 950000, 'Bãi Sao, An Thới, Phú Quốc', 4.6, 920),
(34, 'Du thuyền Sea Coral Nha Trang sang trọng', 'uploads/cruise34.png', 'Trải nghiệm tiệc tối lãng mạn ngắm hoàng hôn vịnh Nha Trang trên du thuyền vỏ thép hiện đại bậc nhất, ca nhạc acoustic sống động.', 1150000, 'Cảng Nha Trang, Vĩnh Nguyên, Nha Trang', 4.8, 1050),
(35, 'Du thuyền Horizon Nha Trang 5 sao', 'uploads/cruise35.png', 'Sở hữu boong tàu ngắm cảnh 360 độ cực rộng, quầy bar ngoài trời phục vụ cocktail mát lạnh và các hoạt động chèo thuyền SUP.', 1200000, 'Cảng Nha Trang, Khánh Hòa', 4.7, 860),
(36, 'Du thuyền Harems Cruise Nha Trang', 'uploads/cruise36.png', 'Du thuyền mang phong cách thiết kế Châu Âu hiện đại với 3 tầng rộng lớn, rạp chiếu phim ngoài trời và tiệc buffet hải sản.', 1300000, 'Cảng Cầu Đá, Nha Trang, Khánh Hòa', 4.6, 680),
(37, 'Du thuyền Poseidon Cruise Nha Trang siêu sang', 'uploads/cruise37.png', 'Lấy cảm hứng từ vị thần biển cả Poseidon, du thuyền có boong tắm nắng dát gỗ tếch sang trọng và hồ bơi jacuzzi ngoài trời.', 1400000, 'Cảng du lịch Nha Trang, Khánh Hòa', 4.8, 1200),
(38, 'Du thuyền Saigon Princess sông Sài Gòn', 'uploads/cruise38.png', 'Du thuyền ẩm thực 5 sao sang trọng trôi trên sông Sài Gòn, ngắm toàn cảnh Landmark 81 nguy nga lộng lẫy về đêm.', 980000, 'Cảng Sài Gòn, Quận 4, TP. Hồ Chí Minh', 4.9, 2150),
(39, 'Du thuyền Indochina Queen sông Sài Gòn', 'uploads/cruise39.png', 'Trải nghiệm tiệc tối buffet ẩm thực Á - Âu phong phú và thưởng thức các tiết mục múa dân tộc đặc sắc dọc sông Sài Gòn.', 550000, 'Cảng Bạch Đằng, Quận 1, TP. Hồ Chí Minh', 4.5, 1780),
(40, 'Du thuyền Bonsai Cruise sông Sài Gòn cổ điển', 'uploads/cruise40.png', 'Du thuyền rồng bằng gỗ nghệ thuật độc đáo, thưởng thức ẩm thực buffet cao cấp và biểu diễn nghệ thuật âm nhạc dân gian.', 850000, 'Cảng Nhà Rồng, Quận 4, TP. Hồ Chí Minh', 4.7, 1420),
(41, 'Du thuyền La Regina Royal Hạ Long', 'uploads/cruise41.png', 'Được mệnh danh là Nữ hoàng của Vịnh Hạ Long, du thuyền hoàng gia sở hữu nội thất gỗ gõ đỏ tinh xảo mang phong cách lịch lãm.', 3300000, 'Cảng tàu khách quốc tế Hạ Long, Quảng Ninh', 4.7, 830),
(42, 'Du thuyền La Regina Grand Lan Hạ', 'uploads/cruise42.png', 'Trải nghiệm hành trình nghỉ dưỡng cao cấp với phòng nghỉ siêu rộng lên tới 45m2 có bồn tắm nằm bằng gỗ bách hương thơm ngát.', 4150000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.8, 1140),
(43, 'Du thuyền La Regina Legend Lan Hạ siêu sang', 'uploads/cruise43.png', 'Nơi hội tụ của những thượng khách tinh tế với thư viện cổ, hầm rượu vang quý hiếm và dịch vụ quản gia cao cấp chuẩn Anh.', 5500000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.9, 1560),
(44, 'Du thuyền Paradise Sails Hạ Long huyền thoại', 'uploads/cruise44.png', 'Du thuyền gỗ phong cách truyền thống nổi tiếng từng tiếp đón nhiều nguyên thủ quốc gia ghé thăm và nghỉ đêm trên vịnh.', 3100000, 'Đảo Tuần Châu, Hạ Long, Quảng Ninh', 4.6, 920),
(45, 'Du thuyền Paradise Peak Hạ Long sang trọng nhất', 'uploads/cruise45.png', 'Đỉnh cao của sự riêng tư với chỉ 8 cabin thượng lưu, toàn bộ phòng nghỉ đều tích hợp phòng xông hơi và bể sục jacuzzi riêng biệt.', 5900000, 'Đảo Tuần Châu, Hạ Long, Quảng Ninh', 4.9, 1280),
(46, 'Du thuyền Calypso Cruise Lan Hạ nổi bật', 'uploads/cruise46.png', 'Du thuyền vỏ thép sơn trắng muốt sang trọng với cột buồm cao vút kiêu hãnh lướt đi qua những đảo đá karst xanh tươi.', 2950000, 'Bến Tuần Châu, Hạ Long, Quảng Ninh', 4.5, 780),
(47, 'Du thuyền Azalea Cruise Lan Hạ cao cấp', 'uploads/cruise47.png', 'Sở hữu phòng suite gia đình cực rộng, quầy bar tầng thượng phục vụ cocktail nhiệt đới và dịch vụ xe limousine đón tiễn.', 3750000, 'Bến phà Got, Cát Hải, Hải Phòng', 4.7, 1020),
(48, 'Du thuyền Mon Chéri Cruise Lan Hạ 2', 'uploads/cruise48.png', 'Du thuyền thân kim loại hiện đại có bể bơi ngoài trời tràn viền tuyệt đẹp, khu vui chơi cho trẻ em an toàn và đầy đủ tiện nghi.', 3700000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.8, 950),
(49, 'Du thuyền Era Cruise Lan Hạ sang xịn mịn', 'uploads/cruise49.png', 'Sở hữu các cabin suite rộng lớn có bồn sục jacuzzi hướng biển cực rộng, ngắm hoàng hôn buông xuống vịnh Lan Hạ từ phòng ngủ.', 4250000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.9, 1380),
(50, 'Du thuyền Oasis Bay Party Cruise Hạ Long', 'uploads/cruise50.png', 'Du thuyền tiệc tùng lớn nhất Hạ Long có bể sục jacuzzi ngoài trời cực lớn, sàn nhảy sôi động cùng hệ thống âm thanh hiện đại.', 2650000, 'Cảng tàu khách quốc tế Tuần Châu, Hạ Long', 4.6, 1120),
(51, 'Du thuyền Serenity Cruise Lan Hạ Catamaran', 'uploads/cruise51.png', 'Chiêm ngưỡng kiến trúc du thuyền tương lai siêu độc đáo, lướt sóng êm ái bằng hệ thống cánh ngầm catamaran tiên tiến nhất.', 4600000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.8, 1470),
(52, 'Du thuyền Margaret Cruise Hạ Long 5 sao', 'uploads/cruise52.png', 'Du thuyền vỏ thép sang trọng mang vẻ đẹp thanh lịch của bông hoa cúc trắng, trang bị spa xông hơi khô hiện đại.', 3200000, 'Cảng tàu khách quốc tế Hạ Long, Bãi Cháy', 4.7, 980),
(53, 'Du thuyền Amanda Cruise Hạ Long sang chảnh', 'uploads/cruise53.png', 'Trải nghiệm trọn vẹn vịnh Hạ Long trên hành trình 2 ngày 1 đêm cao cấp, tham quan Hang Luồn bằng thuyền nan truyền thống.', 2850000, 'Cảng tàu khách quốc tế Tuần Châu, Quảng Ninh', 4.5, 870),
(54, 'Du thuyền Athena Royal Cruise Hạ Long', 'uploads/cruise54.png', 'Sự pha trộn hoàn mỹ giữa phong cách tân cổ điển hoàng gia và nét đẹp hiện đại, sở hữu cabin siêu vip hướng trực diện mũi tàu.', 4100000, 'Cảng tàu khách quốc tế Hạ Long, Bãi Cháy', 4.8, 1260),
(55, 'Du thuyền Signature Royal Halong Cruise', 'uploads/cruise55.png', 'Du thuyền bằng gỗ gõ đỏ tinh xảo có bồn tắm jacuzzi trong phòng, lớp học thái cực quyền đón bình minh thanh bình trên vịnh.', 3800000, 'Cảng tàu khách quốc tế Hạ Long, Quảng Ninh', 4.7, 1020),
(56, 'Du thuyền Aclass Stellar Cruise Hạ Long', 'uploads/cruise56.png', 'Du thuyền phong cách gỗ ấm cúng mang lại cảm giác thân thuộc như ngôi nhà thứ hai, thích hợp cho nhóm bạn trẻ du lịch bụi.', 2500000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.5, 670),
(57, 'Du thuyền Aclass Legend Cruise Hạ Long', 'uploads/cruise57.png', 'Trải nghiệm du lịch vịnh Hạ Long mộc mạc yên bình, chèo kayak khám phá hồ Ba Hầm hoang sơ và lặn ngắm rạn san hô.', 2400000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.4, 580),
(58, 'Du thuyền Carina Cruise Lan Hạ xinh xắn', 'uploads/cruise58.png', 'Chỉ có 9 cabin bằng gỗ tự nhiên đem đến không gian nghỉ dưỡng vô cùng yên bình riêng tư, tránh xa sự ồn ào đô thị.', 2700000, 'Bến phà Tuần Châu, Hạ Long (Vịnh Lan Hạ)', 4.5, 730),
(59, 'Du thuyền Lavender Cruise Hạ Long lãng mạn', 'uploads/cruise59.png', 'Du thuyền gỗ ấm cúng mang hương thơm nhẹ nhàng từ hoa oải hương lavender thư thái, lý tưởng cho những chuyến đi ngắn ngày.', 2300000, 'Cảng tàu khách quốc tế Hạ Long, Quảng Ninh', 4.4, 690),
(60, 'Du thuyền Phoenix Cruise Hạ Long cổ truyền', 'uploads/cruise60.png', 'Du thuyền mang hình dáng chim phượng hoàng lửa phương Đông lộng lẫy, lớp học làm nem cuốn truyền thống thú vị trên boong tàu.', 2450000, 'Cảng Tuần Châu, Hạ Long, Quảng Ninh', 4.5, 810);
INSERT INTO `thuexe` (`id`, `name`, `image`, `description`, `price`, `address`, `rating`, `views`) VALUES
(1, 'Kia Morning 2021 (Tự lái)', 'uploads/car1.png', 'Dòng xe Hatchback 4 chỗ nhỏ gọn, số tự động, tiết kiệm nhiên liệu, rất thích hợp đi lại trong nội thành Đà Nẵng.', 550000, 'Quận Hải Châu, Đà Nẵng', 4.4, 439),
(2, 'Hyundai Grand i10 2022 (Tự lái)', 'uploads/car2.png', 'Hatchback 4 chỗ rộng rãi, số sàn êm ái, thích hợp cho gia đình nhỏ đi du lịch dã ngoại hoặc công tác ngắn ngày.', 580000, 'Quận Hoàn Kiếm, Hà Nội', 4.4, 385),
(3, 'VinFast Fadil 1.4 Premium (Tự lái)', 'uploads/car3.png', 'Dòng xe Hatchback phân khúc A mạnh mẽ bậc nhất, số tự động vô cấp CVT, trang bị hệ thống an toàn tối ưu.', 600000, 'Quận 1, TP. Hồ Chí Minh', 4.4, 364),
(4, 'Toyota Vios 1.5G 2021 (Tự lái)', 'uploads/car4.png', 'Dòng sedan 5 chỗ quốc dân, số tự động, khoang hành lý rộng rãi, xe vận hành bền bỉ, tiết kiệm nhiên liệu.', 750000, 'Quận Sơn Trà, Đà Nẵng', 4.3, 192),
(5, 'Honda City RS 2022 (Tự lái)', 'uploads/car5.png', 'Sedan 5 chỗ thể thao cá tính, số tự động vô cấp CVT, nội thất bọc da pha nỉ hiện đại, điều hòa mát sâu.', 800000, 'Quận Cầu Giấy, Hà Nội', 4.6, 305),
(6, 'Hyundai Accent Athletic 2022 (Tự lái)', 'uploads/car6.png', 'Sedan 5 chỗ kiểu dáng trẻ trung năng động, số tự động, có trang bị cửa sổ trời và bản đồ định vị thông minh.', 780000, 'Quận 3, TP. Hồ Chí Minh', 4.7, 336),
(7, 'Mazda 3 Premium 2022 (Tự lái)', 'uploads/car7.png', 'Sedan phân khúc C cao cấp kiểu dáng Kodo sang trọng thời thượng, số tự động, hỗ trợ Apple CarPlay không dây.', 950000, 'Quận Tây Hồ, Hà Nội', 4.9, 482),
(8, 'Kia K3 Luxury 1.6 2022 (Tự lái)', 'uploads/car8.png', 'Sedan 5 chỗ ngồi rộng rãi thoải mái bậc nhất, số tự động, trang bị điều hòa độc lập và sạc không dây.', 900000, 'Quận Ngũ Hành Sơn, Đà Nẵng', 4.5, 127),
(9, 'Hyundai Elantra 2.0 2021 (Tự lái)', 'uploads/car9.png', 'Dòng sedan thể thao cao cấp, số tự động, không gian lái yên tĩnh, giảm chấn cực tốt mang lại hành trình thoải mái.', 880000, 'Quận Tân Bình, TP. Hồ Chí Minh', 4.8, 353),
(10, 'Honda Civic RS Turbo 2022 (Tự lái)', 'uploads/car10.png', 'Sedan thể thao đẳng cấp cao, động cơ tăng áp 1.5L VTEC Turbo cực bốc, trang bị gói an toàn thông minh Honda Sensing.', 1100000, 'Quận Long Biên, Hà Nội', 4.4, 465),
(11, 'Toyota Camry 2.5Q 2021 (Tự lái)', 'uploads/car11.png', 'Sedan hạng D sang trọng đẳng cấp, số tự động, hàng ghế sau ngả lưng chỉnh điện và hệ thống âm thanh JBL cao cấp.', 1400000, 'Quận 7, TP. Hồ Chí Minh', 4.2, 342),
(12, 'Mazda 6 Signature 2021 (Tự lái)', 'uploads/car12.png', 'Sedan hạng D thời thượng phong cách thể thao, trang bị phanh tay điện tử, màn hình HUD và camera 360 sắc nét.', 1300000, 'Quận Hải Châu, Đà Nẵng', 4.8, 163),
(13, 'VinFast Lux A2.0 Premium (Tự lái)', 'uploads/car13.png', 'Sedan hạng E cao cấp gầm bệ chắc chắn chuẩn Đức, động cơ 2.0L tăng áp dẫn động cầu sau cho cảm giác lái đầm chắc.', 1200000, 'Quận Đống Đa, Hà Nội', 4.3, 273),
(14, 'VinFast VF e34 Điện (Tự lái)', 'uploads/car14.png', 'Dòng Crossover điện thông minh 5 chỗ rộng rãi, sạc nhanh tiện lợi, tích hợp trợ lý ảo tiếng Việt cực kỳ thông minh.', 800000, 'Quận Liên Chiểu, Đà Nẵng', 4.9, 318),
(15, 'VinFast VF 8 Plus Điện (Tự lái)', 'uploads/car15.png', 'SUV điện 5 chỗ thông minh cao cấp, động cơ điện kép dẫn động 4 bánh siêu tốc độ, trang bị hỗ trợ lái nâng cao ADAS.', 1400000, 'Quận Hoàn Kiếm, Hà Nội', 4.8, 437),
(16, 'VinFast VF 9 Plus Điện (Có tài)', 'uploads/car16.png', 'Siêu SUV điện 7 chỗ cỡ lớn, ghế thương gia tích hợp massage thông gió cao cấp, phù hợp đưa đón tiếp khách VIP.', 2500000, 'Quận 2, TP. Hồ Chí Minh', 4.3, 440),
(17, 'Mercedes-Benz C200 Avantgarde 2021 (Có tài)', 'uploads/car17.png', 'Sedan hạng sang từ hãng xe Đức, xe hoa đám cưới lịch lãm hoặc đưa đón hội nghị VIP kèm tài xế chuyên nghiệp.', 2800000, 'Quận 3, TP. Hồ Chí Minh', 5, 287),
(18, 'Mercedes-Benz E300 AMG 2022 (Có tài)', 'uploads/car18.png', 'Sedan hạng sang cao cấp, nội thất ốp gỗ cao cấp và đèn viền 64 màu, phục vụ khách hàng thượng lưu chu đáo nhất.', 3800000, 'Quận Hoàn Kiếm, Hà Nội', 4.5, 357),
(19, 'BMW 520i M Sport 2022 (Có tài)', 'uploads/car19.png', 'Xe sang phong cách thể thao mạnh mẽ Đức, xe luôn được vệ sinh sạch sẽ thơm tho, phục vụ đưa đón đúng giờ.', 3800000, 'Quận 1, TP. Hồ Chí Minh', 4.2, 445),
(20, 'Lexus RX350 Premium 2021 (Có tài)', 'uploads/car20.png', 'SUV hạng sang Nhật Bản vận hành êm ái cách âm tuyệt đối, mang lại trải nghiệm đỉnh cao cho hành trình tiếp khách.', 4200000, 'Quận Hải Châu, Đà Nẵng', 4.3, 375),
(21, 'Mitsubishi Xpander Premium 2022 (Tự lái)', 'uploads/car21.png', 'Xe đa dụng MPV 7 chỗ bán chạy nhất Việt Nam, gầm cao thoáng đạt, số tự động lái nhẹ nhàng và tiết kiệm nhiên liệu.', 850000, 'Quận Cẩm Lệ, Đà Nẵng', 4.8, 449),
(22, 'Toyota Veloz Cross Top 2022 (Tự lái)', 'uploads/car22.png', 'MPV 7 chỗ thông minh, số tự động CVT, sạc điện thoại không dây, màn hình trần giải trí cho hành khách phía sau.', 950000, 'Quận Thanh Xuân, Hà Nội', 4.9, 359),
