(82, 'Mazda CX-8 Premium 2021 (Tự lái)', 'uploads/car82.png', 'SUV 7 chỗ cỡ lớn rộng rãi êm ái, bọc da nappa cao cấp, trang bị loa Bose và camera 360 độ siêu nét.', 1400000, 'Quận 1, TP. Hồ Chí Minh', 4.5, 303),
(83, 'Hyundai Palisade Exclusive 2023 (Tự lái)', 'uploads/car83.png', 'SUV 7 chỗ cỡ lớn bề thế lịch lãm, động cơ dầu 2.2L êm ái, thích hợp cho chuyến đi gia đình đông người tiện lợi.', 1700000, 'Quận Hải Châu, Đà Nẵng', 4.4, 260),
(84, 'Ford Explorer Limited 2022 (Có tài)', 'uploads/car84.png', 'SUV 7 chỗ nhập khẩu Mỹ siêu sang trọng, động cơ tăng áp EcoBoost 2.3L mạnh mẽ, tài xế phục vụ suốt tuyến.', 2500000, 'Quận Tây Hồ, Hà Nội', 4.7, 168),
(85, 'Peugeot 5008 AL 2022 (Tự lái)', 'uploads/car85.png', 'SUV 7 chỗ thương hiệu Pháp thiết kế khoang lái mô phỏng chuyên cơ hiện đại, ghế lái massage cao cấp thư giãn.', 1400000, 'Quận Bình Thạnh, TP. Hồ Chí Minh', 4.6, 144),
(86, 'Subaru Forester i-S EyeSight 2021 (Tự lái)', 'uploads/car86.png', 'SUV 5 chỗ nhập khẩu an toàn bậc nhất thế giới, dẫn động 4 bánh toàn thời gian đối xứng S-AWD vượt trội mọi địa hình.', 1200000, 'Quận Liên Chiểu, Đà Nẵng', 4.6, 257),
(87, 'Jeep Wrangler Rubicon 2021 (Tự lái)', 'uploads/car87.png', 'SUV off-road huyền thoại Mỹ mui trần cá tính bụi bặm, động cơ 2.0L tăng áp vượt địa hình đồi cát cực đỉnh.', 3000000, 'Quận Sơn Trà, Đà Nẵng', 4.6, 134),
(88, 'Chevrolet Trailblazer Dầu 2019 (Tự lái)', 'uploads/car88.png', 'SUV 7 chỗ gầm cao mạnh mẽ cơ bắp Mỹ máy dầu số tự động, xe cực đầm chắc chạy đường trường đèo dốc rất đã.', 1100000, 'Quận Đống Đa, Hà Nội', 4.4, 479),
(89, 'Nissan Terra V 2020 (Tự lái)', 'uploads/car89.png', 'SUV 7 chỗ gầm cao nhập khẩu số tự động dẫn động 2 cầu mạnh mẽ bền bỉ vượt mọi cát đá lầy lội công trình.', 1100000, 'Quận Gò Vấp, TP. Hồ Chí Minh', 4.7, 229),
(90, 'Thaco Town 29 chỗ bầu hơi (Có tài)', 'uploads/car90.png', 'Dòng xe khách 29 chỗ bầu hơi hiện đại, tivi lcd, dàn karaoke giải trí sống động suốt hành trình dài.', 2700000, 'Quận Long Biên, Hà Nội', 4.9, 116),
(91, 'Samco Growin Li 29 chỗ (Có tài)', 'uploads/car91.png', 'Xe du lịch 29 chỗ ngồi thiết kế sang trọng đời mới, ghế bọc da êm ái ngả lưng sâu thoải mái cho khách.', 2800000, 'Quận Hải Châu, Đà Nẵng', 4.9, 71),
(92, 'Hyundai Aero Space 45 chỗ (Có tài)', 'uploads/car92.png', 'Xe du lịch 45 chỗ ngồi thực dụng bền bỉ, lái xe nhiều năm kinh nghiệm chạy các tuyến Tây Bắc, Đông Bắc an toàn.', 3500000, 'Quận 3, TP. Hồ Chí Minh', 4.6, 117),
(93, 'Hyundai Universe Prime 45 chỗ (Có tài)', 'uploads/car93.png', 'Siêu xe du lịch 45 chỗ Universe đời mới nội thất hoàng gia lộng lẫy, đầy đủ tiện nghi giải trí tủ lạnh mini.', 4200000, 'Quận 2, TP. Hồ Chí Minh', 4.2, 374),
(94, 'VinFast VF 5 Plus Điện (Tự lái)', 'uploads/car94.png', 'Hatchback điện cỡ nhỏ thông minh thời thượng thích hợp đi lại luồn lách đô thị chật hẹp vô cùng tiện lợi.', 600000, 'Quận Sơn Trà, Đà Nẵng', 4.9, 243),
(95, 'VinFast VF 6 Plus 2023 (Tự lái)', 'uploads/car95.png', 'Crossover điện 5 chỗ thông minh hiện đại, trợ lý ảo tiếng Việt, camera 360 và gói an toàn thông minh ADAS.', 900000, 'Quận Cầu Giấy, Hà Nội', 4.2, 454),
(96, 'VinFast VF 7 Plus 2024 (Tự lái)', 'uploads/car96.png', 'SUV điện 5 chỗ thiết kế tương lai ấn tượng thể thao, động cơ điện kép siêu mạnh mẽ cực bốc lái phấn khích.', 1200000, 'Quận Tân Bình, TP. Hồ Chí Minh', 4.9, 194),
(97, 'Toyota Land Cruiser Prado 2021 (Có tài)', 'uploads/car97.png', 'SUV gầm cao hạng sang Nhật Bản phục vụ đưa đón nguyên thủ, chuyên gia đi công tác vùng cao, đồi núi đầm chắc.', 3000000, 'Quận Tây Hồ, Hà Nội', 4.4, 133),
(98, 'Mercedes-Benz S450 Luxury 2022 (Có tài)', 'uploads/car98.png', 'Sedan siêu sang Mercedes S-Class, nội thất thương gia thượng lưu, lái xe phục vụ chuẩn nghi thức ngoại giao lịch lãm.', 5000000, 'Quận 1, TP. Hồ Chí Minh', 5, 99),
(99, 'BMW 730Li M Sport 2022 (Có tài)', 'uploads/car99.png', 'Sedan hạng sang đầu bảng BMW Series 7, thiết kế thể thao kiêu hãnh, tài xế phục vụ chu đáo lịch thiệp đúng giờ.', 5000000, 'Quận Hải Châu, Đà Nẵng', 4.5, 269),
(100, 'Audi A8L Premium 2021 (Có tài)', 'uploads/car100.png', 'Sedan hạng sang cỡ lớn Audi A8L, đèn pha Matrix led đỉnh cao, trải nghiệm cabin yên tĩnh cách âm tuyệt đối.', 5500000, 'Quận Hoàn Kiếm, Hà Nội', 4.7, 189);
INSERT INTO `leucamtrai` (`id`, `name`, `image`, `description`, `price`, `address`, `rating`, `views`) VALUES
(1, 'Lều cắm trại đơn BeachBasic T-001', 'uploads/tent1.png', 'Lều đơn 1 người gọn nhẹ, chống thấm tốt, thiết kế thông minh tự bung, thích hợp cho dân phượt bụi tự trải nghiệm bãi biển hoang sơ. Trải nghiệm tại Bãi Sao, Phú Quốc thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 140000, 'Bãi Sao, Phú Quốc', 4.4, 256),
(2, 'Lều dã ngoại đôi OceanBreeze T-002', 'uploads/tent2.png', 'Lều đôi 2 người thoáng khí với 2 cửa sổ lưới đón gió biển, khung sợi thủy tinh chắc chắn chống chịu gió cát tốt. Trải nghiệm tại Bãi Khem, Phú Quốc thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 240000, 'Bãi Khem, Phú Quốc', 4.8, 259),
(3, 'Lều mái vòm Dome Deluxe T-003', 'uploads/tent3.png', 'Lều dome 3-4 người hình bán cầu chống bão cát biển, lớp phủ chống tia UV, không gian cắm trại ấm cúng cho nhóm bạn. Trải nghiệm tại Bãi Dài, Phú Quốc thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 430000, 'Bãi Dài, Phú Quốc', 4.8, 302),
(4, 'Lều gia đình Family Outwell T-004', 'uploads/tent4.png', 'Lều lớn 6 người chia làm 2 buồng ngủ riêng biệt và 1 phòng sinh hoạt chung, thích hợp cho kỳ nghỉ cắm trại gia đình bên bờ biển. Trải nghiệm tại Bãi Mỹ Khê, Đà Nẵng thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 730000, 'Bãi Mỹ Khê, Đà Nẵng', 4.9, 35),
(5, 'Lều Glamping Dome Sang Trọng T-005', 'uploads/tent5.png', 'Lều mái vòm Glamping cao cấp đường kính 4m, đầy đủ đệm hơi, quạt máy, đèn lồng vintage và bàn ghế thư giãn ngoài trời. Trải nghiệm tại Bãi Non Nước, Đà Nẵng thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 1150000, 'Bãi Non Nước, Đà Nẵng', 4.5, 268),
(6, 'Lều Safari Glamping Cao Cấp T-006', 'uploads/tent6.png', 'Lều mui trần phong cách Safari châu Phi sang trọng, chất liệu vải canvas cao cấp cách nhiệt, sàn gỗ nâng cao tránh cát ẩm. Trải nghiệm tại Bãi Nam, Bán đảo Sơn Trà thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 1850000, 'Bãi Nam, Bán đảo Sơn Trà', 4.5, 145),
(7, 'Lều dã ngoại chống gió biển T-007', 'uploads/tent7.png', 'Lều chuyên dụng chống gió to sát biển, trang bị cọc ghim thép đúc và dây neo chịu lực tốt, chống mưa rào. Trải nghiệm tại Bãi Trước, Vũng Tàu thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 360000, 'Bãi Trước, Vũng Tàu', 4.9, 285),
(8, 'Lều tự bung thông minh Speedy T-008', 'uploads/tent8.png', 'Lều tự bung chỉ trong 30 giây cực kỳ tiện lợi, thiết kế 2 lớp chống đọng sương ban đêm bên bờ biển. Trải nghiệm tại Bãi Sau, Vũng Tàu thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 300000, 'Bãi Sau, Vũng Tàu', 4.4, 188),
(9, 'Lều Glamping Oasis Luxury T-009', 'uploads/tent9.png', 'Lều Glamping cỡ lớn đầy đủ nội thất sang trọng: giường đệm cao su, điều hòa mini di động, bàn trà, view trực diện đón bình minh biển. Trải nghiệm tại Bãi Dứa, Vũng Tàu thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 2160000, 'Bãi Dứa, Vũng Tàu', 4.6, 243),
(10, 'Lều võng cắm trại độc đáo T-010', 'uploads/tent10.png', 'Lều kết hợp võng treo giữa hai rặng dừa sát biển, lớp lưới chống muỗi và bạt che mưa chắn gió lộng gió. Trải nghiệm tại Bãi Kỳ Co, Quy Nhơn thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 200000, 'Bãi Kỳ Co, Quy Nhơn', 4.6, 329),
(11, 'Lều cắm trại đơn BeachBasic T-011', 'uploads/tent11.png', 'Lều đơn 1 người gọn nhẹ, chống thấm tốt, thiết kế thông minh tự bung, thích hợp cho dân phượt bụi tự trải nghiệm bãi biển hoang sơ. Trải nghiệm tại Bãi Eo Gió, Quy Nhơn thơ mộng. Dịch vụ thuê trọn gói bao gồm cọc neo cát, thảm cách nhiệt và hệ thống chiếu sáng ban đêm.', 140000, 'Bãi Eo Gió, Quy Nhơn', 4.4, 215),
