-- Tạo cơ sở dữ liệu cho dự án Web Travel
CREATE DATABASE IF NOT EXISTS `web_travel` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `web_travel`;

DROP TABLE IF EXISTS `bill_detail`;
DROP TABLE IF EXISTS `bill`;
DROP TABLE IF EXISTS `binhluan`;
DROP TABLE IF EXISTS `sanpham`;
DROP TABLE IF EXISTS `danhmuc`;
DROP TABLE IF EXISTS `khachsan`;
DROP TABLE IF EXISTS `taikhoan`;
DROP TABLE IF EXISTS `diemden`;
DROP TABLE IF EXISTS `tintuc`;
DROP TABLE IF EXISTS `banner`;
DROP TABLE IF EXISTS `dichvu`;
DROP TABLE IF EXISTS `nhahang`;

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `danhmuc`
--
CREATE TABLE IF NOT EXISTS `danhmuc` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu cho bảng `danhmuc`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `sanpham`
--
CREATE TABLE IF NOT EXISTS `sanpham` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `price` double NOT NULL DEFAULT 0,
  `price_sale` double DEFAULT 0,
  `image` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `views` int(11) NOT NULL DEFAULT 0,
  `id_danhmuc` int(11) NOT NULL,
  `duration` varchar(50) DEFAULT '3 ngày 2 đêm',
  PRIMARY KEY (`id`),
  KEY `fk_sanpham_danhmuc` (`id_danhmuc`),
  CONSTRAINT `fk_sanpham_danhmuc` FOREIGN KEY (`id_danhmuc`) REFERENCES `danhmuc` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu mẫu cho bảng `sanpham`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `taikhoan`
--
CREATE TABLE IF NOT EXISTS `taikhoan` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL UNIQUE,
  `password` varchar(255) NOT NULL,
  `email` varchar(100) NOT NULL UNIQUE,
  `phone` varchar(20) DEFAULT NULL UNIQUE,
  `role` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=143 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm tài khoản quản trị mặc định (mật khẩu là 'admin123' đã băm hoặc lưu text tùy biến, ở đây lưu plain text hoặc md5/password_hash để test dễ dàng, ta sẽ dùng password_hash trong code PHP, tài khoản này sẽ được tạo trong DB)
-- admin: admin123

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `khachsan`
--
CREATE TABLE IF NOT EXISTS `khachsan` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `address` varchar(255) NOT NULL,
  `stars` int(11) NOT NULL DEFAULT 4,
  `price` double NOT NULL DEFAULT 0,
  `price_sale` double DEFAULT 0,
  `image` varchar(255) NOT NULL,
  `location` varchar(100) NOT NULL,
  `views` int(11) NOT NULL DEFAULT 0,
  `category` varchar(100) DEFAULT 'Khách sạn',
  `region` varchar(50) DEFAULT 'Miền Bắc',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu mẫu cho bảng `khachsan`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `diemden`
--
CREATE TABLE IF NOT EXISTS `diemden` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `image` varchar(255) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu mẫu cho bảng `diemden`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `tintuc`
--
CREATE TABLE IF NOT EXISTS `tintuc` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `image` varchar(255) NOT NULL,
  `description` text NOT NULL,
  `date` varchar(50) NOT NULL DEFAULT '02 Th11',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu mẫu cho bảng `tintuc`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `banner`
--
CREATE TABLE IF NOT EXISTS `banner` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `image` varchar(255) NOT NULL,
  `url` varchar(255) NOT NULL,
  `position` varchar(50) NOT NULL,
  `tag` varchar(255) DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL,
  `subtitle` varchar(255) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `btn_text` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu mẫu cho bảng `banner`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `binhluan`
--
CREATE TABLE IF NOT EXISTS `binhluan` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `content` text NOT NULL,
  `id_user` int(11) NOT NULL,
  `id_pro` int(11) NOT NULL,
  `date` varchar(50) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_binhluan_taikhoan` (`id_user`),
  KEY `fk_binhluan_sanpham` (`id_pro`),
  CONSTRAINT `fk_binhluan_taikhoan` FOREIGN KEY (`id_user`) REFERENCES `taikhoan` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_binhluan_sanpham` FOREIGN KEY (`id_pro`) REFERENCES `sanpham` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Thêm dữ liệu mẫu cho bảng `binhluan`

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `bill`
--
CREATE TABLE IF NOT EXISTS `bill` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `bill_code` varchar(50) NOT NULL UNIQUE,
  `id_user` int(11) DEFAULT NULL,
  `bill_name` varchar(255) NOT NULL,
  `bill_email` varchar(100) NOT NULL,
  `bill_phone` varchar(20) NOT NULL,
  `bill_address` varchar(255) NOT NULL,
  `bill_pttt` int(11) NOT NULL DEFAULT 0, -- 0: Chuyển khoản, 1: Trực tiếp khi đi tour
  `bill_total` double NOT NULL DEFAULT 0,
  `bill_status` int(11) NOT NULL DEFAULT 0, -- 0: Chờ xác nhận, 1: Đang chuẩn bị, 2: Đã khởi hành, 3: Đã huỷ
  `date_booking` varchar(50) NOT NULL,
  PRIMARY KEY (`id`),
  CONSTRAINT `fk_bill_taikhoan` FOREIGN KEY (`id_user`) REFERENCES `taikhoan` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `bill_detail`
--
CREATE TABLE IF NOT EXISTS `bill_detail` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_bill` int(11) NOT NULL,
  `id_pro` int(11) NOT NULL,
  `name` varchar(255) NOT NULL,
  `image` varchar(255) NOT NULL,
  `price` double NOT NULL DEFAULT 0,
  `quantity` int(11) NOT NULL DEFAULT 1,
  `total` double NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  CONSTRAINT `fk_detail_bill` FOREIGN KEY (`id_bill`) REFERENCES `bill` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------
-- Cấu trúc bảng cho bảng `dichvu`
--
CREATE TABLE IF NOT EXISTS `dichvu` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `icon` varchar(100) DEFAULT '💼',
  `description` text DEFAULT NULL,
  `price` double NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

